import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const mountApp = () => {
  const rootElement = document.getElementById('root');
  if (!rootElement) {
    console.error("Could not find root element to mount to");
    return;
  }

  const root = ReactDOM.createRoot(rootElement);
  root.render(
    <React.StrictMode>
      <App />
    </React.StrictMode>
  );
};

// Garante que o DOM está pronto antes de montar
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', mountApp);
} else {
  mountApp();
}

import React, { useState, useRef, useMemo, FormEvent, useEffect, useCallback } from 'react';
import { Product, Supplier, StockMovement, ParsedNFe, Employee, PriceHistory, Category, ToastMessage, NFe, WorkOrder, User } from '../types';
import { Table, SortConfig } from './shared/Table';
import { Modal } from './shared/Modal';
import { parseNFeXML } from '../services/nfeParser';
import { parseInvoicePDF } from '../services/geminiService';
import { CameraModal } from './shared/CameraModal';
import { useSupabase } from '../contexts/SupabaseContext';
import { QRCodeScannerModal } from './shared/QRCodeScannerModal';


interface StockControlProps {
  addToast: (message: string, type: ToastMessage['type']) => void;
  showConfirmation: (message: string, onConfirm: () => void) => void;
  addActivityLog: (action: string) => void;
  currentUser: User;
}

export const StockControl: React.FC<StockControlProps> = ({ 
    addToast, showConfirmation, addActivityLog, currentUser
}) => {
  const supabase = useSupabase();

  const [products, setProducts] = useState<Product[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [priceHistory, setPriceHistory] = useState<PriceHistory[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [workOrders, setWorkOrders] = useState<WorkOrder[]>([]);
  const [stockMovements, setStockMovements] = useState<StockMovement[]>([]);

  useEffect(() => {
    const fetchData = async () => {
        const [prodRes, supRes, empRes, priceRes, catRes, woRes, smRes] = await Promise.all([
            supabase.from('products').select('*'),
            supabase.from('suppliers').select('*'),
            supabase.from('employees').select('*'),
            supabase.from('price_history').select('*'),
            supabase.from('categories').select('*'),
            supabase.from('work_orders').select('*'),
            supabase.from('stock_movements').select('*')
        ]);
        if(prodRes.data) setProducts(prodRes.data as unknown as Product[]);
        if(supRes.data) setSuppliers(supRes.data);
        if(empRes.data) setEmployees(empRes.data);
        if(priceRes.data) setPriceHistory(priceRes.data);
        if(catRes.data) setCategories(catRes.data);
        if(woRes.data) setWorkOrders(woRes.data as unknown as WorkOrder[]);
        if(smRes.data) setStockMovements(smRes.data as unknown as StockMovement[]);
    };
    fetchData();

    const channel = supabase.channel('stock-control-db-changes');

    const tablesToSubscribe = [
        { table: 'products', setter: setProducts },
        { table: 'suppliers', setter: setSuppliers },
        { table: 'employees', setter: setEmployees },
        { table: 'price_history', setter: setPriceHistory },
        { table: 'categories', setter: setCategories },
        { table: 'work_orders', setter: setWorkOrders },
        { table: 'stock_movements', setter: setStockMovements }
    ];

    tablesToSubscribe.forEach(({ table, setter }) => {
      channel.on('postgres_changes', { event: '*', schema: 'public', table }, (payload) => {
        if (payload.eventType === 'INSERT') {
          setter(current => {
            if (current.some(item => item.id === payload.new.id)) return current;
            return [...current, payload.new as any];
          });
        }
        if (payload.eventType === 'UPDATE') {
          setter(current => current.map(item => item.id === payload.new.id ? payload.new as any : item));
        }
        if (payload.eventType === 'DELETE') {
          setter(current => current.filter(item => item.id !== payload.old.id));
        }
      });
    });

    channel.subscribe();

    return () => {
        supabase.removeChannel(channel);
    };

  }, [supabase]);


  const [isNFeModalOpen, setIsNFeModalOpen] = useState(false);
  const [isOutModalOpen, setIsOutModalOpen] = useState(false);
  const [isPriceHistoryModalOpen, setIsPriceHistoryModalOpen] = useState(false);
  const [isProductModalOpen, setIsProductModalOpen] = useState(false);
  const [isReceiptModalOpen, setIsReceiptModalOpen] = useState(false);
  const [isCameraModalOpen, setIsCameraModalOpen] = useState(false);
  const [isScannerOpen, setIsScannerOpen] = useState(false);
  const [isLabelModalOpen, setIsLabelModalOpen] = useState(false);

  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [currentProduct, setCurrentProduct] = useState<Partial<Product> | null>(null);

  // State for Multi-Scan Outflow
  const [multiScanItems, setMultiScanItems] = useState<{product: Product, quantity: number}[]>([]);
  const [isMultiScanActive, setIsMultiScanActive] = useState(false);

  const [receiptData, setReceiptData] = useState({
    productId: '',
    quantity: 1,
    unitPrice: '',
    photo: '',
    photoName: ''
  });

  const [outQuantity, setOutQuantity] = useState<number | string>(1);
  const [outEmployeeId, setOutEmployeeId] = useState<string>('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [nfeData, setNfeData] = useState<ParsedNFe | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<SortConfig<Product> | null>(null);
  const [selectedItems, setSelectedItems] = useState<string[]>([]);
  const [categoryFilter, setCategoryFilter] = useState<string>('');
  const [outWorkOrderId, setOutWorkOrderId] = useState<string>('');

  const checkLowStock = useCallback(async (product: Product, newQuantity: number) => {
    const minStock = product.min_stock || 10;
    if (newQuantity <= minStock) {
        const { data: existing } = await supabase
            .from('notifications')
            .select('*')
            .eq('product_id', product.id)
            .eq('read', false)
            .limit(1);

        if (!existing || existing.length === 0) {
            await supabase.from('notifications').insert({
                message: `Estoque Baixo: O produto "${product.name}" atingiu ${newQuantity} unidades (Mínimo: ${minStock}).`,
                product_id: product.id,
                read: false
            });
        }
    }
  }, [supabase]);

  const filteredProducts = useMemo(() => {
    return products.filter(p =>
      (p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      p.id.toLowerCase().includes(searchTerm.toLowerCase())) &&
      (categoryFilter === '' || p.category_id === categoryFilter)
    );
  }, [products, searchTerm, categoryFilter]);

  const requestSort = (key: keyof Product) => {
    let direction: 'ascending' | 'descending' = 'ascending';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'ascending') {
        direction = 'descending';
    }
    setSortConfig({ key, direction });
  };

  const sortedProducts = useMemo(() => {
      let sortableItems = [...filteredProducts];
      if (sortConfig !== null) {
          sortableItems.sort((a, b) => {
              const valA = a[sortConfig.key];
              const valB = b[sortConfig.key];
              if (typeof valA === 'number' && typeof valB === 'number') {
                  if (valA < valB) return sortConfig.direction === 'ascending' ? -1 : 1;
                  if (valA > valB) return sortConfig.direction === 'ascending' ? 1 : -1;
                  return 0;
              }
              const strA = String(valA || '').toLowerCase();
              const strB = String(valB || '').toLowerCase();
              if (strA < strB) return sortConfig.direction === 'ascending' ? -1 : 1;
              if (strA > strB) return sortConfig.direction === 'ascending' ? 1 : -1;
              return 0;
          });
      }
      return sortableItems;
  }, [filteredProducts, sortConfig]);

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setIsLoading(true);
      setError(null);
      setNfeData(null);

      if (file.type === 'application/pdf') {
          const reader = new FileReader();
          reader.onload = async (e) => {
              try {
                  const base64 = (e.target?.result as string).split(',')[1];
                  const parsedData = await parseInvoicePDF(base64);
                  setNfeData(parsedData);
              } catch (err) {
                  setError(err instanceof Error ? err.message : 'Erro ao processar PDF com IA');
              } finally {
                  setIsLoading(false);
              }
          };
          reader.readAsDataURL(file);
      } else {
          const reader = new FileReader();
          reader.onload = async (e) => {
              try {
                  const content = e.target?.result as string;
                  const parsedData = await parseNFeXML(content);
                  setNfeData(parsedData);
              } catch (err) {
                  setError(err instanceof Error ? err.message : 'Erro ao processar XML');
              } finally {
                  setIsLoading(false);
              }
          };
          reader.readAsText(file);
      }
    }
  };

  const addStockMovement = useCallback(async (movement: Omit<StockMovement, 'id' | 'date' | 'user_id'>) => {
    const { data, error } = await supabase.from('stock_movements').insert({ ...movement, date: new Date().toISOString() }).select().single();
    if(error) {
        addToast(`Erro ao registrar movimento: ${error.message}`, 'error');
    } else if(data) {
        setStockMovements(prev => [...prev, data as unknown as StockMovement]);
    }
  }, [addToast, supabase]);

  const addNf = useCallback(async (nf: Omit<NFe, 'id' | 'user_id'>) => {
    const { error } = await supabase.from('nfs').insert(nf as any).select().single();
    if(error) {
        addToast(`Erro ao salvar NF: ${error.message}`, 'error');
    }
  }, [addToast, supabase]);


  const confirmNFeImport = async () => {
    if (!nfeData) return;

    let supplier = suppliers.find(s => s.cnpj === nfeData.supplier.cnpj);

    if (!supplier && nfeData.supplier.cnpj) {
        const { data: existingData } = await supabase
            .from('suppliers')
            .select('*')
            .eq('cnpj', nfeData.supplier.cnpj)
            .maybeSingle();

        if (existingData) {
            supplier = existingData;
            if (!suppliers.some(s => s.id === existingData.id)) {
                setSuppliers(prev => [...prev, existingData]);
            }
        } else {
            const { data: newlyCreatedSupplierData, error: insertError } = await supabase
                .from('suppliers')
                .insert({
                    name: nfeData.supplier.name,
                    cnpj: nfeData.supplier.cnpj,
                })
                .select(); 

            if (insertError) {
                addToast(`Erro ao criar novo fornecedor: ${insertError.message}`, 'error');
                return;
            }

            if (newlyCreatedSupplierData && newlyCreatedSupplierData.length > 0) {
                supplier = newlyCreatedSupplierData[0];
                if (supplier) setSuppliers(prev => [...prev, supplier as Supplier]);
            }
        }
    }

    const consolidatedNfeProducts = new Map<string, { name: string, quantity: number, unit_price: number }>();

    for (const p of nfeData.products) {
        if (consolidatedNfeProducts.has(p.code)) {
            const existing = consolidatedNfeProducts.get(p.code)!;
            consolidatedNfeProducts.set(p.code, {
                ...existing,
                quantity: existing.quantity + p.quantity,
                unit_price: p.unit_price 
            });
        } else {
            consolidatedNfeProducts.set(p.code, { name: p.name, quantity: p.quantity, unit_price: p.unit_price });
        }
    }

    const productsToUpsert = [];
    const movementsToInsert = [];
    const pricesToInsert = [];

    for (const [code, data] of consolidatedNfeProducts.entries()) {
        const existingProduct = products.find(p => p.id === code);
        const newQuantity = (existingProduct ? existingProduct.quantity : 0) + data.quantity;

        productsToUpsert.push({
            id: code,
            name: data.name,
            quantity: newQuantity,
            unit_price: data.unit_price,
        });

        const lastPriceEntry = priceHistory
            .filter(ph => ph.product_id === code)
            .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())[0];

        const lastPrice = lastPriceEntry ? lastPriceEntry.price : (existingProduct ? existingProduct.unit_price : 0);

        if (data.unit_price !== lastPrice) {
            pricesToInsert.push({
                product_id: code,
                price: data.unit_price,
                date: new Date().toISOString(),
            });
        }

        movementsToInsert.push({
            product_id: code,
            product_name: data.name,
            type: 'in' as const,
            quantity: data.quantity,
            reason: `NF-e ${nfeData.supplier.cnpj} (Consolidado)`,
        });
    }

    setProducts(prev => {
        const updated = [...prev];
        productsToUpsert.forEach(upserted => {
            const idx = updated.findIndex(p => p.id === upserted.id);
            if (idx >= 0) updated[idx] = { ...updated[idx], ...upserted };
            else updated.push(upserted as Product);
        });
        return updated;
    });

    const { error: productsError } = await supabase.from('products').upsert(productsToUpsert);
    if (productsError) {
        addToast(`Erro ao atualizar produtos: ${productsError.message}`, 'error');
        return;
    }

    const { data: insertedMovements, error: movementsError } = await supabase.from('stock_movements').insert(movementsToInsert).select();
    if (movementsError) {
        addToast(`Erro ao registrar movimentos: ${movementsError.message}`, 'error');
    } else if (insertedMovements) {
        setStockMovements(prev => [...prev, ...(insertedMovements as unknown as StockMovement[])]);
    }

    if (pricesToInsert.length > 0) {
        const { error: pricesError } = await supabase.from('price_history').insert(pricesToInsert);
        if (pricesError) addToast(`Erro ao salvar histórico de preços: ${pricesError.message}`, 'warning');
    }

    const totalValue = nfeData.products.reduce((acc, prod) => acc + (prod.quantity * prod.unit_price), 0);
    const newNf: Omit<NFe, 'id' | 'user_id'> = {
        supplier: nfeData.supplier,
        products: nfeData.products,
        total_value: totalValue,
        import_date: new Date().toISOString(),
    };
    await addNf(newNf);

    addActivityLog(`importou NF-e de ${nfeData.supplier.name}.`);
    addToast(`${consolidatedNfeProducts.size} tipos de produtos importados com sucesso!`, 'success');
    closeNFeModal();
  };

  const handleProductSubmit = async (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);

    const id = currentProduct?.id ? currentProduct.id : (formData.get('id') as string);

    const productData = {
        id: id,
        name: formData.get('name') as string,
        quantity: parseFloat(formData.get('quantity') as string),
        unit_price: parseFloat(formData.get('unitPrice') as string),
        category_id: formData.get('categoryId') as string || null,
        min_stock: parseFloat(formData.get('minStock') as string) || 0,
        location_aisle: formData.get('location_aisle') as string || null,
        location_shelf: formData.get('location_shelf') as string || null,
        location_bin: formData.get('location_bin') as string || null,
    };

    if (!currentProduct?.id && products.some(p => p.id === id)) {
        addToast('Erro: Já existe um produto com este código.', 'error');
        return;
    }

    if (currentProduct?.id) {
        const originalProducts = products;
        setProducts(prev => prev.map(p => p.id === currentProduct.id ? { ...p, ...productData } : p));
        const { error } = await supabase.from('products').update(productData).eq('id', currentProduct.id);
        if (error) {
            addToast(`Erro ao atualizar: ${error.message}`, 'error');
            setProducts(originalProducts);
        } else {
            addToast('Produto atualizado com sucesso!', 'success');
            addActivityLog(`atualizou o produto: ${productData.name}.`);
            checkLowStock({ ...originalProducts.find(p => p.id === id), ...productData } as Product, productData.quantity);
        }
    } else {
        const { data, error } = await supabase.from('products').insert(productData).select().single();
        if (error) {
             addToast(`Erro ao criar: ${error.message}`, 'error');
        } else if (data) {
             setProducts(prev => [...prev, data as unknown as Product]);
             await addStockMovement({
                product_id: id,
                product_name: productData.name,
                type: 'in',
                quantity: productData.quantity,
                reason: 'Cadastro manual'
            });
            const { error: priceError } = await supabase.from('price_history').insert({
                product_id: id,
                price: productData.unit_price,
                date: new Date().toISOString()
            });
            if (priceError) addToast(`Erro ao salvar preço: ${priceError.message}`, 'warning');
            addToast('Produto cadastrado com sucesso!', 'success');
            addActivityLog(`cadastrou o produto: ${productData.name}.`);
            checkLowStock(data as unknown as Product, productData.quantity);
        }
    }

    closeProductModal();
  };

  const handleDeleteProduct = (id: string, name: string) => {
    showConfirmation('Tem certeza que deseja excluir este produto?', async () => {
        const originalProducts = products;
        setProducts(prev => prev.filter(p => p.id !== id));
        const { error } = await supabase.from('products').delete().eq('id', id);
        if (error) {
            addToast(`Erro ao excluir: ${error.message}`, 'error');
            setProducts(originalProducts);
        } else {
            addToast('Produto excluído com sucesso!', 'success');
            addActivityLog(`excluiu o produto: ${name}.`);
        }
    });
  }

  const handleDeleteSelected = () => {
      showConfirmation(`Tem certeza que deseja excluir ${selectedItems.length} produtos?`, async () => {
          const originalProducts = products;
          const selectedNames = products.filter(p => selectedItems.includes(p.id)).map(p => p.name).join(', ');
          setProducts(prev => prev.filter(p => !selectedItems.includes(p.id)));
          const { error } = await supabase.from('products').delete().in('id', selectedItems);
          if (error) {
               addToast(`Erro ao excluir: ${error.message}`, 'error');
               setProducts(originalProducts);
          } else {
            addToast(`${selectedItems.length} produtos excluídos com sucesso!`, 'success');
            addActivityLog(`excluiu ${selectedItems.length} produtos: ${selectedNames}.`);
            setSelectedItems([]);
          }
      });
  }

  const handleReceiptPhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        const reader = new FileReader();
        reader.onloadend = () => {
            setReceiptData(prev => ({ ...prev, photo: reader.result as string, photoName: file.name }));
        };
        reader.readAsDataURL(file);
    }
  };

   const handleCameraCapture = (imageData: string) => {
    setReceiptData(prev => ({ ...prev, photo: imageData, photoName: `captura_${Date.now()}.jpg` }));
    setIsCameraModalOpen(false);
  };

  const handleReceiptSubmit = async (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const { productId, quantity, unitPrice, photo } = receiptData;
    const product = products.find(p => p.id === productId);

    if (!product || quantity <= 0) {
        addToast("Produto ou quantidade inválida.", "error");
        return;
    }

    const newQuantity = product.quantity + quantity;
    const newPrice = unitPrice ? parseFloat(unitPrice) : product.unit_price;

    const originalProducts = products;
    setProducts(prev => prev.map(p => p.id === productId ? { ...p, quantity: newQuantity, unit_price: newPrice } : p));

    const { error: updateError } = await supabase
        .from('products')
        .update({ quantity: newQuantity, unit_price: newPrice })
        .eq('id', productId);

    if (updateError) {
        addToast(`Erro ao atualizar produto: ${updateError.message}`, 'error');
        setProducts(originalProducts);
        return;
    }

    await addStockMovement({
        product_id: product.id,
        product_name: product.name,
        type: 'in',
        quantity: quantity,
        reason: 'Entrada avulsa com comprovante',
        receipt_photo: photo
    });

    if (unitPrice) {
        const { error: priceError } = await supabase.from('price_history').insert({
            product_id: product.id,
            price: parseFloat(unitPrice),
            date: new Date().toISOString()
        });
        if (priceError) addToast(`Erro ao salvar histórico de preço: ${priceError.message}`, 'warning');
    }

    addToast("Entrada avulsa registrada com sucesso!", "success");
    addActivityLog(`registrou entrada avulsa de ${quantity}x ${product.name}.`);
    closeReceiptModal();
  };

  const closeNFeModal = () => {
    setIsNFeModalOpen(false);
    setNfeData(null);
    setError(null);
    if(fileInputRef.current) fileInputRef.current.value = "";
  }

  const openOutModal = (product: Product) => {
    setSelectedProduct(product);
    setOutQuantity(1);
    setOutEmployeeId(employees.length > 0 ? employees[0].id : '');
    setOutWorkOrderId('');
    setIsOutModalOpen(true);
  };

  const openProductModal = (product: Product | null) => {
    setCurrentProduct(product ? {...product} : { id: '', name: '', quantity: 0, unit_price: 0, min_stock: 10, location_aisle: '', location_shelf: '', location_bin: '' });
    setIsProductModalOpen(true);
  };

  const closeProductModal = () => {
    setCurrentProduct(null);
    setIsProductModalOpen(false);
  };

  const openPriceHistoryModal = (product: Product) => {
    setSelectedProduct(product);
    setIsPriceHistoryModalOpen(true);
  };

  const closePriceHistoryModal = () => {
    setIsPriceHistoryModalOpen(false);
    setSelectedProduct(null);
  };

  const openReceiptModal = () => {
    setReceiptData({ productId: products.length > 0 ? products[0].id : '', quantity: 1, unitPrice: '', photo: '', photoName: '' });
    setIsReceiptModalOpen(true);
  }

  const closeReceiptModal = () => {
    setIsReceiptModalOpen(false);
  }

  const handleScan = (code: string) => {
      // Find product by scanned code
      const product = products.find(p => p.id === code);
      if (product) {
          if (isMultiScanActive) {
              setMultiScanItems(prev => {
                  const existing = prev.find(i => i.product.id === product.id);
                  if (existing) {
                      return prev.map(i => i.product.id === product.id ? {...i, quantity: i.quantity + 1} : i);
                  }
                  return [...prev, { product, quantity: 1 }];
              });
              addToast(`${product.name} adicionado à lista.`, 'success');
          } else {
              setSearchTerm(code);
              addToast(`Produto ${product.name} localizado!`, 'success');
              setIsScannerOpen(false);
          }
      } else {
          addToast(`Código ${code} não encontrado no estoque.`, 'warning');
      }
  };

  const handleStockOut = async () => {
    const quantity = Number(outQuantity);
    if (!selectedProduct || quantity <= 0 || quantity > selectedProduct.quantity) {
      addToast("Quantidade de saída inválida.", 'error');
      return;
    }
    if (!outEmployeeId) {
        addToast("Por favor, selecione um funcionário.", 'error');
        return;
    }

    const originalProduct = products.find(p => p.id === selectedProduct.id);
    if (!originalProduct) return;

    const newQuantity = originalProduct.quantity - quantity;
    setProducts(prev => prev.map(p => p.id === originalProduct.id ? {...p, quantity: newQuantity} : p));

    const { error } = await supabase
        .from('products')
        .update({ quantity: newQuantity })
        .eq('id', selectedProduct.id);

    if (error) {
        addToast(`Erro ao atualizar estoque: ${error.message}`, 'error');
        setProducts(prev => prev.map(p => p.id === originalProduct.id ? originalProduct : p));
        return;
    }

    const employee = employees.find(e => e.id === outEmployeeId);
    const workOrder = workOrders.find(wo => wo.id === outWorkOrderId);

    const reason = workOrder 
        ? `para OS "${workOrder.title}" por ${employee?.name}`
        : `Uso geral por ${employee?.name}`;

    await addStockMovement({
      product_id: selectedProduct.id,
      product_name: selectedProduct.name,
      type: 'out',
      quantity: quantity,
      reason: reason,
      employee_id: outEmployeeId,
      employee_name: employee ? employee.name : undefined,
      work_order_id: outWorkOrderId || undefined,
    });

    addActivityLog(`registrou saída de ${quantity}x ${selectedProduct.name}.`);
    addToast('Saída de estoque registrada com sucesso!', 'success');
    checkLowStock(originalProduct, newQuantity);

    setIsOutModalOpen(false);
    setSelectedProduct(null);
  };

  const handleMultiStockOutConfirm = async () => {
      if (multiScanItems.length === 0 || !outEmployeeId) {
          addToast("Selecione um funcionário e ao menos um item.", 'error');
          return;
      }

      setIsLoading(true);
      const employee = employees.find(e => e.id === outEmployeeId);
      const workOrder = workOrders.find(wo => wo.id === outWorkOrderId);

      try {
          for (const item of multiScanItems) {
              const newQty = item.product.quantity - item.quantity;
              const { error } = await supabase.from('products').update({ quantity: newQty }).eq('id', item.product.id);
              if (error) throw error;

              await addStockMovement({
                product_id: item.product.id,
                product_name: item.product.name,
                type: 'out',
                quantity: item.quantity,
                reason: workOrder ? `OS: ${workOrder.title} (Multi-Scan)` : `Uso geral por ${employee?.name} (Multi-Scan)`,
                employee_id: outEmployeeId,
                employee_name: employee?.name,
                work_order_id: outWorkOrderId || undefined
              });
              checkLowStock(item.product, newQty);
          }
          addToast(`${multiScanItems.length} itens removidos com sucesso!`, 'success');
          addActivityLog(`registrou saída multi-scan de ${multiScanItems.length} produtos.`);
          setMultiScanItems([]);
          setIsOutModalOpen(false);
      } catch (e: any) {
          addToast(`Erro no processamento: ${e.message}`, 'error');
      } finally {
          setIsLoading(false);
      }
  };

  const productPriceHistory = useMemo(() => {
    if (!selectedProduct) return [];
    return priceHistory
      .filter(h => h.product_id === selectedProduct.id)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [priceHistory, selectedProduct]);

  const columns = [
    { header: 'Código', accessor: 'id' as const, sortable: true },
    { header: 'Nome', accessor: 'name' as const, sortable: true },
    { header: 'Localização', accessor: (item: Product) => (
        <span className="text-xs font-mono bg-gray-100 dark:bg-gray-700 px-1.5 py-0.5 rounded text-gray-600 dark:text-gray-300">
            {item.location_aisle || '?'}-{item.location_shelf || '?'}-{item.location_bin || '?'}
        </span>
    ), sortable: true, sortKey: 'location_aisle' as any },
    { header: 'Quantidade', accessor: 'quantity' as const, sortable: true },
    { header: 'Preço Unitário', accessor: (item: Product) => (currentUser.role !== 'stockist' ? item.unit_price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }) : '***'), sortable: currentUser.role !== 'stockist', sortKey: 'unit_price' as const},
  ];

  const formInputClass = "mt-1 block w-full border border-gray-300 rounded-md shadow-sm py-2 px-3 focus:outline-none focus:ring-primary focus:border-primary sm:text-sm dark:bg-gray-700 dark:border-gray-600 dark:text-gray-200";

  const handlePrintLabels = () => {
      setIsLabelModalOpen(true);
  }

  const handleDownloadPickingList = () => {
    // Sort products by location for efficient picking
    const productsToPick = [...products]
        .filter(p => p.quantity > 0)
        .sort((a, b) => {
            const locA = `${a.location_aisle || ''}${a.location_shelf || ''}${a.location_bin || ''}`;
            const locB = `${b.location_aisle || ''}${b.location_shelf || ''}${b.location_bin || ''}`;
            return locA.localeCompare(locB);
        });

    const headers = { aisle: 'Corredor', shelf: 'Prateleira', bin: 'Gaveta', id: 'Código', name: 'Nome', qty: 'Qtd Atual' };
    const data = productsToPick.map(p => ({
        aisle: p.location_aisle || '-',
        shelf: p.location_shelf || '-',
        bin: p.location_bin || '-',
        id: p.id,
        name: p.name,
        qty: p.quantity
    }));

    let csv = Object.values(headers).join(',') + '\n';
    data.forEach(row => {
        csv += Object.values(row).join(',') + '\n';
    });

    const blob = new Blob([`\uFEFF${csv}`], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `Picking_List_${new Date().toLocaleDateString('pt-BR')}.csv`;
    link.click();
    addToast('Lista de separação gerada com sucesso!', 'success');
  };

  return (
    <div className="space-y-6">
      <div className="sm:flex justify-between items-center">
        <div>
            <h2 className="text-2xl font-bold text-gray-800 dark:text-gray-200">Controle de Estoque</h2>
            <p className="text-gray-500 dark:text-gray-400">Logística, Etiquetas e Saídas Rápidas.</p>
        </div>
        <div className="flex flex-wrap gap-2 mt-4 sm:mt-0">
            <button onClick={handleDownloadPickingList} className="bg-orange-600 text-white px-4 py-2 rounded-lg shadow hover:bg-orange-700 transition flex items-center">
                <svg className="w-5 h-5 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" /></svg>
                Lista Picking
            </button>
            <button onClick={handlePrintLabels} className="bg-purple-600 text-white px-4 py-2 rounded-lg shadow hover:bg-purple-700 transition flex items-center">
                <svg className="w-5 h-5 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z" /></svg>
                Imprimir Etiquetas
            </button>
            <button onClick={() => { setIsMultiScanActive(true); setIsScannerOpen(true); setMultiScanItems([]); setSelectedProduct(null); setIsOutModalOpen(true); }} className="bg-indigo-600 text-white px-4 py-2 rounded-lg shadow hover:bg-indigo-700 transition flex items-center">
                <svg className="w-5 h-5 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" /></svg>
                Saída Contínua
            </button>
            <button onClick={() => openProductModal(null)} className="bg-green-600 text-white px-4 py-2 rounded-lg shadow hover:bg-green-700 transition">
                Novo Produto
            </button>
        </div>
      </div>

       <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="relative">
            <input
                type="text"
                placeholder="Buscar por código ou nome do produto..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 border rounded-lg dark:bg-gray-800 dark:border-gray-600 dark:text-gray-200"
            />
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <svg className="h-5 w-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
            </div>
          </div>
           <div>
               <select
                   value={categoryFilter}
                   onChange={(e) => setCategoryFilter(e.target.value)}
                   className="w-full px-4 py-2 border rounded-lg dark:bg-gray-800 dark:border-gray-600 dark:text-gray-200"
               >
                   <option value="">Todas as Categorias</option>
                   {categories.map(cat => (
                       <option key={cat.id} value={cat.id}>{cat.name}</option>
                   ))}
               </select>
           </div>
      </div>

      <Table<Product>
        columns={columns}
        data={sortedProducts}
        actions={(product) => (
          <>
            <button onClick={() => openOutModal(product)} title="Saída de Estoque" className="text-yellow-600 hover:text-yellow-900 dark:text-yellow-400 dark:hover:text-blue-300 p-1 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M13 7l5 5m0 0l-5 5m5-5H6" />
                </svg>
            </button>
            <button onClick={() => openProductModal(product)} title="Editar" className="text-indigo-600 hover:text-indigo-900 dark:text-indigo-400 dark:hover:text-indigo-300 p-1 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                    <path strokeLinecap="round" strokeLinejoin="round" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                </svg>
            </button>
            <button onClick={() => handleDeleteProduct(product.id, product.name)} title="Excluir" className="text-red-600 hover:text-red-900 dark:text-red-400 dark:hover:text-red-300 p-1 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                    <path strokeLinecap="round" strokeLinejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
            </button>
          </>
        )}
        sortConfig={sortConfig}
        requestSort={requestSort}
        selectedItems={selectedItems}
        setSelectedItems={setSelectedItems}
      />

      <Modal isOpen={isOutModalOpen} onClose={() => { setIsOutModalOpen(false); setIsMultiScanActive(false); }} title={isMultiScanActive ? "Saída de Estoque Contínua" : "Registrar Saída de Estoque"}>
        <div className="space-y-4">
            {!isMultiScanActive && selectedProduct && (
                <>
                    <p><strong>Produto:</strong> {selectedProduct.name}</p>
                    <p><strong>Estoque atual:</strong> {selectedProduct.quantity}</p>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Quantidade</label>
                        <input type="number" value={outQuantity} onChange={e => setOutQuantity(e.target.value)} className={formInputClass} />
                    </div>
                </>
            )}

            {isMultiScanActive && (
                <div className="space-y-2">
                    <button onClick={() => setIsScannerOpen(true)} className="w-full bg-indigo-600 text-white py-2 rounded-lg font-bold flex justify-center items-center">
                        <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" /></svg>
                        Escanear Próximo
                    </button>
                    <div className="max-h-40 overflow-y-auto border dark:border-gray-700 rounded-md p-2 space-y-1">
                        {multiScanItems.length > 0 ? multiScanItems.map((item, idx) => (
                            <div key={idx} className="flex justify-between text-xs bg-gray-50 dark:bg-gray-800 p-1.5 rounded">
                                <span className="truncate flex-1">{item.product.name}</span>
                                <span className="font-bold ml-2">x{item.quantity}</span>
                            </div>
                        )) : <p className="text-center text-gray-500 text-xs py-4">Nenhum item escaneado.</p>}
                    </div>
                </div>
            )}

            <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Funcionário</label>
                <select value={outEmployeeId} onChange={e => setOutEmployeeId(e.target.value)} className={formInputClass} required>
                  <option value="">Selecione...</option>
                  {employees.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
                </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Ordem de Serviço (Opcional)</label>
              <select value={outWorkOrderId} onChange={(e) => setOutWorkOrderId(e.target.value)} className={formInputClass}>
                  <option value="">Uso Geral</option>
                  {workOrders.filter(wo => wo.status !== 'completed').map(wo => (
                      <option key={wo.id} value={wo.id}>{wo.title}</option>
                  ))}
              </select>
            </div>
            <button 
                onClick={isMultiScanActive ? handleMultiStockOutConfirm : handleStockOut} 
                disabled={isLoading}
                className="bg-red-600 text-white px-4 py-2 rounded w-full font-bold shadow hover:bg-red-700 transition"
            >
                {isLoading ? "Processando..." : "Confirmar Saída"}
            </button>
        </div>
      </Modal>

      <Modal isOpen={isProductModalOpen} onClose={closeProductModal} title={currentProduct?.id ? 'Editar Produto' : 'Novo Produto'}>
        <form onSubmit={handleProductSubmit} className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Código/EAN do Produto</label>
                    <input type="text" name="id" defaultValue={currentProduct?.id} required className={formInputClass} disabled={!!currentProduct?.id}/>
                </div>
                <div className="col-span-2">
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Nome do Produto</label>
                    <input type="text" name="name" defaultValue={currentProduct?.name} required className={formInputClass}/>
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Categoria</label>
                    <select name="categoryId" defaultValue={currentProduct?.category_id || ''} className={formInputClass}>
                        <option value="">Sem Categoria</option>
                        {categories.map(cat => <option key={cat.id} value={cat.id}>{cat.name}</option>)}
                    </select>
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Estoque Mínimo</label>
                    <input type="number" name="minStock" defaultValue={currentProduct?.min_stock || 10} required className={formInputClass}/>
                </div>
            </div>

            <div className="border-t dark:border-gray-700 pt-4">
                <h4 className="text-sm font-bold text-gray-600 dark:text-gray-400 mb-2 uppercase tracking-tight">Localização no Depósito</h4>
                <div className="grid grid-cols-3 gap-2">
                    <div>
                        <label className="text-xs text-gray-500">Corredor</label>
                        <input type="text" name="location_aisle" defaultValue={currentProduct?.location_aisle || ''} placeholder="Ex: A" className={formInputClass}/>
                    </div>
                    <div>
                        <label className="text-xs text-gray-500">Prateleira</label>
                        <input type="text" name="location_shelf" defaultValue={currentProduct?.location_shelf || ''} placeholder="Ex: 03" className={formInputClass}/>
                    </div>
                    <div>
                        <label className="text-xs text-gray-500">Gaveta/Caixa</label>
                        <input type="text" name="location_bin" defaultValue={currentProduct?.location_bin || ''} placeholder="Ex: 12" className={formInputClass}/>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Qtd Inicial</label>
                    <input type="number" step="0.01" name="quantity" defaultValue={currentProduct?.quantity} required className={formInputClass}/>
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Custo Unitário (R$)</label>
                    <input type="number" step="0.01" name="unitPrice" defaultValue={currentProduct?.unit_price} required className={formInputClass}/>
                </div>
            </div>

            <div className="flex justify-end pt-4 space-x-2">
                <button type="button" onClick={closeProductModal} className="bg-gray-200 text-gray-800 px-4 py-2 rounded-lg hover:bg-gray-300">Cancelar</button>
                <button type="submit" className="bg-primary text-white px-4 py-2 rounded-lg hover:bg-secondary">Salvar</button>
            </div>
        </form>
      </Modal>

      <Modal isOpen={isLabelModalOpen} onClose={() => setIsLabelModalOpen(false)} title="Etiquetas para Impressão">
          <div className="space-y-6">
              <p className="text-sm text-gray-500">Exibindo etiquetas de todos os produtos com estoque. Use <b>Ctrl+P</b> para imprimir.</p>
              <div id="printable-labels" className="grid grid-cols-2 gap-4 max-h-[60vh] overflow-y-auto p-2">
                  {products.filter(p => p.quantity > 0).map(p => (
                      <div key={p.id} className="border-2 border-dashed border-gray-300 p-2 rounded flex items-center space-x-2 bg-white text-black">
                          <img 
                            src={`https://api.qrserver.com/v1/create-qr-code/?size=80x80&data=${encodeURIComponent(p.id)}`} 
                            alt="QR" 
                            className="w-16 h-16"
                          />
                          <div className="flex-1 overflow-hidden">
                              <p className="text-[10px] font-bold truncate leading-tight uppercase">{p.name}</p>
                              <p className="text-[9px] font-mono text-gray-600 leading-none mt-1">ID: {p.id}</p>
                              <p className="text-[9px] font-bold text-blue-700 mt-1">Loc: {p.location_aisle || '?'}-{p.location_shelf || '?'}-{p.location_bin || '?'}</p>
                          </div>
                      </div>
                  ))}
              </div>
              <button onClick={() => window.print()} className="w-full bg-blue-600 text-white py-2 rounded shadow-lg font-bold">Imprimir Agora</button>
          </div>
      </Modal>

      <QRCodeScannerModal 
        isOpen={isScannerOpen} 
        onClose={() => { setIsScannerOpen(false); setIsMultiScanActive(false); }} 
        onScan={handleScan}
        addToast={addToast}
      />

      {/* Print styles */}
      <style>{`
        @media print {
            body * { visibility: hidden; }
            #printable-labels, #printable-labels * { visibility: visible; }
            #printable-labels { 
                position: absolute; 
                left: 0; 
                top: 0; 
                width: 100%; 
                grid-template-columns: repeat(3, 1fr) !important;
            }
        }
      `}</style>
    </div>
  );
};

export type UserRole = 'admin' | 'manager' | 'stockist';

export interface Product {
  id: string;
  name: string;
  quantity: number;
  unit_price: number;
  category_id?: string | null;
  min_stock?: number | null;
  // Fix: Added location fields to the Product interface.
  location_aisle?: string | null;
  location_shelf?: string | null;
  location_bin?: string | null;
  user_id?: string;
  created_at?: string;
}

export interface Supplier {
  id: string;
  name: string;
  cnpj: string;
  contact?: string | null;
  address?: string | null;
  whatsapp?: string | null;
  user_id?: string;
  created_at?: string;
}

export interface Client {
  id: string;
  name: string;
  cpf: string;
  birth_date?: string | null; // Format YYYY-MM-DD
  email?: string | null;
  phone?: string | null;
  address?: string | null;
  city?: string | null;
  state?: string | null;
  zip_code?: string | null;
  user_id?: string;
  created_at?: string;
}

export interface Employee {
  id: string;
  name: string;
  role: string;
  contact?: string | null;
  user_id?: string;
  created_at?: string;
}

export interface User {
  id: string;
  name: string;
  email?: string;
  role: UserRole;
  password?: string; // Should be hashed in a real app
  organization_id?: string;
}

export interface StockMovement {
  id: string;
  product_id: string;
  product_name: string;
  type: 'in' | 'out';
  quantity: number;
  date: string;
  reason?: string | null;
  employee_id?: string | null;
  employee_name?: string | null;
  receipt_photo?: string | null;
  work_order_id?: string | null;
  user_id?: string;
}

export interface NFeProduct {
  code: string;
  name: string;
  quantity: number;
  unit_price: number;
}

export interface NFeSupplier {
  name: string;
  cnpj: string;
}

export interface ParsedNFe {
  supplier: NFeSupplier;
  products: NFeProduct[];
}

export interface NFe {
  id: string;
  supplier: NFeSupplier;
  products: NFeProduct[];
  total_value: number;
  import_date: string; // ISO string
