}

export interface Asset {
  id:string;
  name: string;
  description: string;
  value: number;
  location: string;
  acquisition_date: string;
  photo?: string | null;
  user_id?: string;
  created_at?: string;
}

export interface MaintenanceRecord {
  id: string;
  asset_id: string;
  date: string;
  description: string;
  cost: number;
  type: 'completed' | 'scheduled';
  user_id?: string;
  created_at?: string;
}

export interface Category {
  id: string;
  name: string;
  user_id?: string;
  created_at?: string;
}

export interface AppNotification {
  id: string;
  message: string;
  read: boolean;
  createdAt: string;
  // Generic IDs for different notification types
  productId?: string;
  assetId?: string;
  maintenanceId?: string;
  user_id?: string;
}


export type ToastMessage = {
  id: string;
  message: string;
  type: 'success' | 'error' | 'info' | 'warning';
};

export interface CarPart {
  id: string; // Part number or custom ID
  name: string;
  description?: string | null;
  vehicle_model?: string | null;
  quantity: number;
  location?: string | null;
  photo?: string | null;
  unit_price: number;
  user_id?: string;
  created_at?: string;
}

export interface QuoteItem {
  id: string; // Unique ID for the item within the quote
  sourceId?: string; // ID of the product or car part, if it's from stock
  name: string;
  quantity: number;
  type: 'product' | 'carPart' | 'manual';
}

export interface Quote {
  id: string;
  title: string;
  created_at: string;
  items: QuoteItem[];
  user_id?: string;
}

export interface WorkOrder {
    id: string;
    title: string;
    status: 'open' | 'in_progress' | 'completed';
    created_at: string;
    items: QuoteItem[];
    user_id?: string;
