      <Modal isOpen={isPriceHistoryModalOpen} onClose={() => setIsPriceHistoryModalOpen(false)} title={`Histórico de Preços: ${currentProduct?.name}`}>
          <div className="space-y-4">
              <div className="max-h-[400px] overflow-y-auto">
                  <table className="w-full text-left">
                      <thead className="bg-gray-50 dark:bg-gray-700 sticky top-0">
                          <tr>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500">Data</th>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500">Fornecedor/Origem</th>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500 text-right">Preço</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y dark:divide-gray-700">
                          {priceHistory.map((h, idx) => (
                              <tr key={idx} className="hover:bg-gray-50 dark:hover:bg-gray-800">
                                  <td className="p-3 text-sm">{new Date(h.date).toLocaleDateString('pt-BR')}</td>
                                  <td className="p-3 text-sm font-medium">{h.supplier_name || 'N/A'}</td>
                                  <td className="p-3 text-sm font-bold text-right text-primary">{h.price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</td>
                              </tr>
                          ))}
                          {priceHistory.length === 0 && (
                              <tr><td colSpan={3} className="p-10 text-center text-gray-400 italic">Sem registros de alteração de preço.</td></tr>
                          )}
                      </tbody>
                  </table>
              </div>
          </div>
      </Modal>

      <Modal isOpen={isProductModalOpen} onClose={() => setIsProductModalOpen(false)} title={currentProduct?.id ? 'Ficha do Produto' : 'Novo Produto'}>
        <form onSubmit={handleProductSubmit} className="space-y-4">
            <div>
                <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Nome Interno</label>
                <input type="text" name="name" defaultValue={currentProduct?.name || ''} required className={formInputClass} />
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">ID Interno</label>
                    <input type="text" name="id" defaultValue={currentProduct?.id || ''} required disabled={!!currentProduct?.id} className={`${formInputClass} bg-gray-50 dark:bg-gray-900 disabled:text-gray-400`} />
                </div>
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Preço Custo (R$)</label>
                    <input type="number" step="0.01" name="unitPrice" defaultValue={currentProduct?.unit_price ?? ''} required className={`${formInputClass} font-bold text-primary`} />
                </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Qtd Atual</label>
                    <input type="number" step="0.01" name="quantity" defaultValue={currentProduct?.quantity ?? ''} required className={formInputClass} />
                </div>
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Mínimo</label>
                    <input type="number" step="1" name="minStock" defaultValue={currentProduct?.min_stock ?? ''} required className={formInputClass} />
                </div>
            </div>
            <button type="submit" className="w-full py-4 bg-primary text-white font-bold rounded-xl shadow-lg mt-4 transition hover:bg-secondary">Gravar Alterações</button>
        </form>
      </Modal>

      <Modal isOpen={isStockModalOpen} onClose={() => setIsStockModalOpen(false)} title={`Movimentação: ${currentProduct?.name}`}>
          <div className="space-y-4">
              <div className="flex justify-between p-4 bg-gray-50 dark:bg-gray-700 rounded-xl border border-gray-100 dark:border-gray-600">
                  <span className="text-gray-500 dark:text-gray-400">Estoque Atual</span>
                  <span className="font-bold text-lg">{currentProduct?.quantity}</span>
              </div>
              <div>
                  <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Quantidade para {stockAction === 'in' ? 'Entrada' : 'Saída'}</label>
                  <input type="number" value={stockQuantity} onChange={e => setStockQuantity(e.target.value)} min="0.01" step="0.01" className={formInputClass} />
              </div>
              {stockAction === 'out' && (
                  <div className="space-y-4">
                    <div>
                        <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Funcionário Responsável</label>
                        <select value={stockEmployeeId} onChange={e => setStockEmployeeId(e.target.value)} className={formInputClass}>
                            <option value="">Selecione...</option>
                            {employees.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
                        </select>
                    </div>
                    <div>
                        <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Ordem de Serviço (Opcional)</label>
                        <select value={stockWorkOrderId} onChange={e => setStockWorkOrderId(e.target.value)} className={formInputClass}>
                            <option value="">Nenhuma / Uso Geral</option>
                            {workOrders.map(wo => <option key={wo.id} value={wo.id}>{wo.title}</option>)}
                        </select>
                    </div>
                  </div>
              )}
              <button onClick={handleStockAction} className={`w-full py-4 rounded-xl font-bold text-white shadow-lg transition ${stockAction === 'in' ? 'bg-green-600 hover:bg-green-700' : 'bg-amber-600 hover:bg-amber-700'}`}>
                  Confirmar {stockAction === 'in' ? 'Entrada' : 'Saída'}
              </button>
          </div>
      </Modal>

      {currentProduct && (
        <QRCodeModal isOpen={isQrModalOpen} onClose={() => setIsQrModalOpen(false)} title={`QR Code: ${currentProduct.name}`} data={currentProduct.id} />
      )}

      <QRCodeScannerModal isOpen={isScannerOpen} onClose={() => setIsScannerOpen(false)} onScan={(data) => { setSearchTerm(data); addToast(`Produto ${data} localizado`, 'success'); }} addToast={addToast} />

    </div>
  );
};

import { ParsedNFe, NFeProduct } from '../types';

/**
 * Limpa o nome do produto removendo códigos aleatórios ou sequências numéricas no final.
 * Ex: "PANO PEGA POERIA ROBERLO 61497" -> "PANO PEGA POERIA ROBERLO"
 */
export const cleanName = (name: string): string => {
    return name
        .replace(/\s+\d+(\-\w+)?$/g, '') // Remove números/códigos no final (ex: 61497 ou 6149-X)
        .replace(/\s{2,}/g, ' ')         // Remove espaços duplos
        .trim();
};

export const parseNFeXML = (xmlString: string): Promise<ParsedNFe> => {
  return new Promise((resolve, reject) => {
    try {
      const parser = new DOMParser();
      const xmlDoc = parser.parseFromString(xmlString, "application/xml");

      const errorNode = xmlDoc.querySelector("parsererror");
      if (errorNode) {
        reject(new Error("Erro ao analisar o XML. Verifique o formato do arquivo."));
        return;
      }

      const infNFe = xmlDoc.querySelector("infNFe");
      const rawId = infNFe?.getAttribute("Id") || "";
      const access_key = rawId.replace("NFe", "");

      if (!access_key || access_key.length !== 44) {
          reject(new Error("Não foi possível identificar uma chave de acesso válida (44 dígitos) neste XML."));
          return;
      }

      const emitNode = xmlDoc.querySelector("emit");
      if (!emitNode) {
        reject(new Error("Não foi possível encontrar os dados do emissor (fornecedor) na NF-e."));
        return;
      }

      const supplier = {
        cnpj: emitNode.querySelector("CNPJ")?.textContent?.trim() || '',
        name: emitNode.querySelector("xNome")?.textContent?.trim() || '',
      };

      if (!supplier.cnpj || !supplier.name) {
          reject(new Error("CNPJ ou Nome do fornecedor não encontrado no XML."));
          return;
      }

      const totalNode = xmlDoc.querySelector("total vNF");
      const total_value = parseFloat(totalNode?.textContent || '0');

      const productNodes = xmlDoc.querySelectorAll("det");
      if (productNodes.length === 0) {
        reject(new Error("Nenhum produto encontrado na NF-e."));
        return;
      }

      const products: NFeProduct[] = Array.from(productNodes).map(node => {
        const prodNode = node.querySelector("prod");
        if (!prodNode) {
          throw new Error("Formato de produto inválido em um dos itens.");
        }
        const rawName = prodNode.querySelector("xProd")?.textContent?.trim() || '';
        return {
          code: prodNode.querySelector("cProd")?.textContent?.trim() || '',
          name: cleanName(rawName), // Aplica limpeza no nome
          quantity: parseFloat(prodNode.querySelector("qCom")?.textContent || '0'),
          unit_price: parseFloat(prodNode.querySelector("vUnCom")?.textContent || '0'),
        };
      });

      resolve({ access_key, supplier, products, total_value });

    } catch (error) {
      reject(new Error(`Falha ao processar o arquivo XML: ${error instanceof Error ? error.message : String(error)}`));
    }
  });
};

import React, { useState, useMemo, FormEvent, useEffect, useCallback } from 'react';
import { Product, Employee, ToastMessage, User, WorkOrder, PriceHistory, ParsedNFe, NFeProduct } from '../types';
import { Table, SortConfig } from './shared/Table';
import { Modal } from './shared/Modal';
import { useSupabase } from '../contexts/SupabaseContext';
import { QRCodeModal } from './shared/QRCodeModal';
import { QRCodeScannerModal } from './shared/QRCodeScannerModal';
import { parseNFeXML, cleanName } from '../services/nfeParser';
import { parseFiscalDocument } from '../services/geminiService';

interface StockControlProps {
  addToast: (message: string, type: ToastMessage['type']) => void;
  showConfirmation: (message: string, onConfirm: () => void) => void;
  addActivityLog: (action: string) => void;
  currentUser: User;
}

export const StockControl: React.FC<StockControlProps> = ({ 
    addToast, showConfirmation, addActivityLog
}) => {
  const supabase = useSupabase();
  const [products, setProducts] = useState<Product[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [workOrders, setWorkOrders] = useState<WorkOrder[]>([]);
  const [priceHistory, setPriceHistory] = useState<PriceHistory[]>([]);
  const [isProcessingIA, setIsProcessingIA] = useState(false);

  // Estados para Revisão de Importação
  const [pendingImport, setPendingImport] = useState<ParsedNFe | null>(null);
  const [mappings, setMappings] = useState<Record<number, string | 'NEW'>>({});

  const fetchData = useCallback(async () => {
    const [p, e, wo] = await Promise.all([
      supabase.from('products').select('*').order('name'),
      supabase.from('employees').select('*'),
      supabase.from('work_orders').select('*'),
    ]);
    if (p.data) setProducts(p.data);
    if (e.data) setEmployees(e.data);
    if (wo.data) setWorkOrders(wo.data as unknown as WorkOrder[]);
  }, [supabase]);

  useEffect(() => {
    fetchData();
    const channel = supabase.channel('products-realtime')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'products' }, () => fetchData())
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [supabase, fetchData]);

  const [isProductModalOpen, setIsProductModalOpen] = useState(false);
  const [isStockModalOpen, setIsStockModalOpen] = useState(false);
  const [isScannerOpen, setIsScannerOpen] = useState(false);
  const [isQrModalOpen, setIsQrModalOpen] = useState(false);
  const [isPriceHistoryModalOpen, setIsPriceHistoryModalOpen] = useState(false);

  const [currentProduct, setCurrentProduct] = useState<Product | null>(null);
  const [stockAction, setStockAction] = useState<'in' | 'out'>('in');
  const [stockQuantity, setStockQuantity] = useState<number | string>(1);
  const [stockEmployeeId, setStockEmployeeId] = useState<string>('');
  const [stockWorkOrderId, setStockWorkOrderId] = useState<string>('');

  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<SortConfig<Product>>(null);

  const filteredProducts = useMemo(() => {
    return products.filter(p =>
      p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      p.id.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [products, searchTerm]);

  const requestSort = (key: keyof Product) => {
    let direction: 'ascending' | 'descending' = 'ascending';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'ascending') {
      direction = 'descending';
    }
    setSortConfig({ key, direction });
  };

  const sortedProducts = useMemo(() => {
    let sortableItems = [...filteredProducts];
    if (sortConfig !== null) {
      sortableItems.sort((a, b) => {
        const valA = a[sortConfig.key] || '';
        const valB = b[sortConfig.key] || '';
        if (valA < valB) return sortConfig.direction === 'ascending' ? -1 : 1;
        if (valA > valB) return sortConfig.direction === 'ascending' ? 1 : -1;
        return 0;
      });
    }
    return sortableItems;
  }, [filteredProducts, sortConfig]);

  // Lógica de mapeamento inteligente na abertura do modal de revisão
  const openReviewModal = (parsed: ParsedNFe) => {
      const initialMappings: Record<number, string | 'NEW'> = {};

      parsed.products.forEach((p, index) => {
          // 1. Tenta por ID exato
          const matchById = products.find(existing => existing.id === p.code);
          if (matchById) {
              initialMappings[index] = matchById.id;
              return;
          }

          // 2. Tenta por Nome exato (limpo)
          const cleanNfeName = cleanName(p.name).toLowerCase();
          const matchByName = products.find(existing => cleanName(existing.name).toLowerCase() === cleanNfeName);
          if (matchByName) {
              initialMappings[index] = matchByName.id;
              return;
          }

          // 3. Senão, marca como NOVO por padrão
          initialMappings[index] = 'NEW';
      });

      setMappings(initialMappings);
      setPendingImport(parsed);
  };

  const confirmFinalImport = async () => {
      if (!pendingImport) return;

      setIsProcessingIA(true);
      try {
          // Registrar a Nota Fiscal
          const { error: nfError } = await supabase.from('nfs').insert({
              supplier: { ...pendingImport.supplier, access_key: pendingImport.access_key || null } as any,
              products: pendingImport.products as any,
              total_value: pendingImport.total_value,
              import_date: new Date().toISOString()
          });

          if (nfError) throw new Error(`Erro ao salvar NF: ${nfError.message}`);

          for (let i = 0; i < pendingImport.products.length; i++) {
              const p = pendingImport.products[i];
              const mappingId = mappings[i];

              let targetId = p.code;
              let isNew = true;

              if (mappingId && mappingId !== 'NEW') {
                  targetId = mappingId;
                  isNew = false;
              }

              const { data: existing } = await supabase.from('products').select('*').eq('id', targetId).maybeSingle();

              // Gravar Histórico
              if (!existing || existing.unit_price !== p.unit_price) {
                  await supabase.from('price_history').insert({
                      product_id: targetId,
                      price: p.unit_price,
                      date: new Date().toISOString(),
                      supplier_name: pendingImport.supplier.name
                  });
              }

              if (existing) {
                  await supabase.from('products').update({ 
                      quantity: existing.quantity + p.quantity,
                      unit_price: p.unit_price 
                  }).eq('id', targetId);
              } else {
                  await supabase.from('products').insert({
                      id: targetId,
                      name: p.name,
                      quantity: p.quantity,
                      unit_price: p.unit_price,
                      min_stock: 0
                  });
              }

              await supabase.from('stock_movements').insert({
                  product_id: targetId,
                  product_name: p.name,
                  type: 'in',
                  quantity: p.quantity,
                  date: new Date().toISOString(),
                  reason: `Importação: ${pendingImport.supplier.name}`
              });
          }

          addToast('Importação concluída com sucesso!', 'success');
          addActivityLog(`importou documento de ${pendingImport.supplier.name} com revisão.`);
          setPendingImport(null);
          await fetchData();
      } catch (err: any) {
          addToast(err.message, 'error');
      } finally {
          setIsProcessingIA(false);
      }
  };

  const handleImportXML = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      try {
        const xml = event.target?.result as string;
        const parsed = await parseNFeXML(xml);
        openReviewModal(parsed);
      } catch (err: any) {
        addToast(`Erro ao processar XML: ${err.message}`, 'error');
      }
    };
    reader.readAsText(file);
    e.target.value = ''; 
  };

  const handleImportCupom = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      setIsProcessingIA(true);
      addToast("Aguarde, a IA está analisando o cupom...", "info");

      const reader = new FileReader();
      reader.onload = async (event) => {
          try {
              const base64 = event.target?.result as string;
              const parsed = await parseFiscalDocument(base64, file.type);
              openReviewModal(parsed);
          } catch (err: any) {
              addToast(err.message || "Erro ao processar cupom com IA.", "error");
          } finally {
              setIsProcessingIA(false);
          }
      };
      reader.readAsDataURL(file);
      e.target.value = '';
  };

  const handleProductSubmit = async (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const name = formData.get('name') as string;
    const unit_price = parseFloat(formData.get('unitPrice') as string);
    const quantity = parseFloat(formData.get('quantity') as string);
    const min_stock = parseFloat(formData.get('minStock') as string);

    if (currentProduct?.id) {
      if (currentProduct.unit_price !== unit_price) {
          await supabase.from('price_history').insert({
              product_id: currentProduct.id,
              price: unit_price,
              date: new Date().toISOString(),
              supplier_name: 'Alteração Manual'
          });
      }

      const { error } = await supabase.from('products').update({
        name, unit_price, quantity, min_stock
      }).eq('id', currentProduct.id);

      if (error) addToast(`Erro ao atualizar: ${error.message}`, 'error');
      else {
        addToast('Produto atualizado!', 'success');
        addActivityLog(`atualizou o produto ${name}`);
        await fetchData();
        setIsProductModalOpen(false);
      }
    } else {
      const id = formData.get('id') as string;
      const { error } = await supabase.from('products').insert({
        id, name, unit_price, quantity, min_stock
      });

      if (error) addToast(`Erro ao cadastrar: ${error.message}`, 'error');
      else {
        await supabase.from('price_history').insert({
            product_id: id,
            price: unit_price,
            date: new Date().toISOString(),
            supplier_name: 'Cadastro Inicial'
        });
        addToast('Produto cadastrado!', 'success');
        addActivityLog(`cadastrou o produto ${name}`);
        await fetchData();
        setIsProductModalOpen(false);
      }
    }
  };

  const handleStockAction = async () => {
    if (!currentProduct) return;
    const qty = parseFloat(stockQuantity as string);
    const newQty = stockAction === 'in' ? currentProduct.quantity + qty : currentProduct.quantity - qty;

    if (newQty < 0) {
      addToast('Erro: Estoque insuficiente.', 'error');
      return;
    }

    const { error } = await supabase.from('products').update({ quantity: newQty }).eq('id', currentProduct.id);
    if (error) {
      addToast(`Erro ao movimentar: ${error.message}`, 'error');
      return;
    }

    const employee = employees.find(e => e.id === stockEmployeeId);
    const movement = {
      product_id: currentProduct.id,
      product_name: currentProduct.name,
      type: stockAction,
      quantity: qty,
      date: new Date().toISOString(),
      employee_id: stockEmployeeId || null,
      employee_name: employee?.name || null,
      work_order_id: stockWorkOrderId || null,
      reason: stockAction === 'in' ? 'Entrada manual' : 'Saída manual',
    };

    await supabase.from('stock_movements').insert(movement);
    addToast('Estoque atualizado!', 'success');
    addActivityLog(`${stockAction === 'in' ? 'entrada' : 'saída'} de ${qty}x ${currentProduct.name}`);
    await fetchData();
    setIsStockModalOpen(false);
  };

  const handleDelete = (product: Product) => {
    showConfirmation(`Deseja excluir o produto ${product.name}?`, async () => {
      const { error } = await supabase.from('products').delete().eq('id', product.id);
      if (error) addToast(`Erro ao excluir: ${error.message}`, 'error');
      else {
        addToast('Produto excluído!', 'success');
        addActivityLog(`excluiu o produto ${product.name}`);
        await fetchData();
      }
    });
  };

  const viewPriceHistory = async (product: Product) => {
      setCurrentProduct(product);
      const { data } = await supabase
        .from('price_history')
        .select('*')
        .eq('product_id', product.id)
        .order('date', { ascending: false });

      if (data) setPriceHistory(data as unknown as PriceHistory[]);
      setIsPriceHistoryModalOpen(true);
  };

  const columns = [
    { header: 'ID', accessor: 'id' as const, sortable: true },
    { header: 'Nome', accessor: 'name' as const, sortable: true },
    { header: 'Qtd', accessor: 'quantity' as const, sortable: true },
    { header: 'Preço', accessor: (item: Product) => item.unit_price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }), sortable: true, sortKey: 'unit_price' as const },
    { header: 'Mínimo', accessor: 'min_stock' as const, sortable: true },
  ];

  const formInputClass = "w-full p-3 border rounded-xl dark:bg-gray-800 dark:border-gray-700 dark:text-gray-200";

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-800 dark:text-gray-200">Controle de Estoque</h2>
          <p className="text-gray-500 dark:text-gray-400">Gerencie seus produtos de consumo e insumos.</p>
        </div>
        <div className="flex flex-wrap gap-2">
            <label className={`bg-amber-600 text-white px-4 py-2 rounded-lg hover:bg-amber-700 transition flex items-center cursor-pointer shadow-lg ${isProcessingIA ? 'opacity-50 pointer-events-none' : ''}`}>
                {isProcessingIA ? (
                    <svg className="animate-spin h-5 w-5 mr-2" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                ) : (
                    <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"></path></svg>
                )}
                Importar Cupom (IA)
                <input type="file" accept="image/*,.pdf" className="hidden" onChange={handleImportCupom} disabled={isProcessingIA} />
            </label>
            <label className="bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition flex items-center cursor-pointer shadow-lg">
                <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
                XML NFe
                <input type="file" accept=".xml" className="hidden" onChange={handleImportXML} />
            </label>
            <button onClick={() => setIsScannerOpen(true)} className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition flex items-center shadow-lg">
                <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg>
                Escanear
            </button>
            <button onClick={() => { setCurrentProduct(null); setIsProductModalOpen(true); }} className="bg-primary text-white px-4 py-2 rounded-lg hover:bg-secondary transition shadow-lg">
                Novo Produto
            </button>
        </div>
      </div>

      <div className="relative">
        <input
          type="text"
          placeholder="Buscar por nome ou ID..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="w-full pl-10 pr-4 py-2 border rounded-lg dark:bg-gray-800 dark:border-gray-600 dark:text-gray-200"
        />
        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
          <svg className="h-5 w-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
        </div>
      </div>

      <Table<Product>
        columns={columns}
        data={sortedProducts}
        sortConfig={sortConfig}
        requestSort={requestSort}
        actions={(product) => (
          <div className="flex space-x-2">
            <button onClick={() => { setCurrentProduct(product); setStockAction('in'); setStockQuantity(1); setIsStockModalOpen(true); }} title="Entrada" className="text-green-600 hover:bg-green-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"></path></svg></button>
            <button onClick={() => { setCurrentProduct(product); setStockAction('out'); setStockQuantity(1); setIsStockModalOpen(true); }} title="Saída" className="text-amber-600 hover:bg-amber-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 12H4"></path></svg></button>
            <button onClick={() => viewPriceHistory(product)} title="Histórico de Preço" className="text-purple-600 hover:bg-purple-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6"></path></svg></button>
            <button onClick={() => { setCurrentProduct(product); setIsQrModalOpen(true); }} title="QR Code" className="text-gray-600 hover:bg-gray-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg></button>
            <button onClick={() => { setCurrentProduct(product); setIsProductModalOpen(true); }} title="Editar" className="text-indigo-600 hover:text-indigo-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg></button>
            <button onClick={() => handleDelete(product)} title="Excluir" className="text-red-600 hover:bg-red-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg></button>
          </div>
        )}
      />

      {/* MODAL DE REVISÃO DE IMPORTAÇÃO */}
      <Modal 
        isOpen={!!pendingImport} 
        onClose={() => setPendingImport(null)} 
        title={`Revisão de Importação: ${pendingImport?.supplier.name}`}
      >
          <div className="space-y-6">
              <p className="text-sm text-gray-500">
                  Verifique os itens abaixo. O sistema sugeriu vínculos baseados no nome ou código. 
                  Você pode escolher "Cadastrar como NOVO" ou selecionar um produto já existente para evitar duplicidade.
              </p>

              <div className="max-h-[500px] overflow-y-auto space-y-4 pr-2">
                  {pendingImport?.products.map((item, idx) => (
                      <div key={idx} className="p-4 border dark:border-gray-700 rounded-xl bg-gray-50 dark:bg-gray-800/50 space-y-3">
                          <div className="flex justify-between items-start">
                              <div className="flex-1">
                                  <h4 className="text-sm font-bold text-gray-800 dark:text-gray-100 uppercase">{item.name}</h4>
                                  <p className="text-[10px] text-gray-500 font-mono">Cód. Nota: {item.code} | Vlr: {item.unit_price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</p>
                              </div>
                              <div className="text-right ml-4">
                                  <span className="text-sm font-bold text-primary">+{item.quantity} un</span>
                              </div>
                          </div>

                          <div>
                              <label className="text-[10px] font-bold uppercase text-gray-400 mb-1 block">Vincular ao Produto:</label>
                              <select 
                                  value={mappings[idx]} 
                                  onChange={e => setMappings(prev => ({...prev, [idx]: e.target.value}))}
                                  className="w-full p-2 text-xs border rounded-lg dark:bg-gray-700 dark:border-gray-600"
                              >
                                  <option value="NEW" className="font-bold text-emerald-600 italic">✨ CADASTRAR COMO NOVO ITEM</option>
                                  <optgroup label="PRODUTOS EM ESTOQUE">
                                      {products.map(p => (
                                          <option key={p.id} value={p.id}>
                                              {p.name} (Saldo: {p.quantity})
                                          </option>
                                      ))}
                                  </optgroup>
                              </select>
                          </div>
                      </div>
                  ))}
              </div>

              <div className="flex flex-col space-y-2">
                  <button 
                      onClick={confirmFinalImport}
                      disabled={isProcessingIA}
                      className="w-full py-4 bg-primary text-white font-bold rounded-xl shadow-lg hover:bg-secondary transition disabled:opacity-50"
                  >
                      {isProcessingIA ? 'Processando...' : 'Confirmar e Alimentar Estoque'}
                  </button>
                  <button onClick={() => setPendingImport(null)} className="w-full py-2 text-sm text-gray-500 hover:text-red-500 transition">Cancelar Importação</button>
              </div>
          </div>
      </Modal>

      {/* Histórico de Preços */}
      <Modal isOpen={isPriceHistoryModalOpen} onClose={() => setIsPriceHistoryModalOpen(false)} title={`Histórico de Preços: ${currentProduct?.name}`}>
          <div className="space-y-4">
              <div className="max-h-[400px] overflow-y-auto">
                  <table className="w-full text-left">
                      <thead className="bg-gray-50 dark:bg-gray-700 sticky top-0">
                          <tr>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500">Data</th>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500">Fornecedor/Origem</th>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500 text-right">Preço</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y dark:divide-gray-700">
                          {priceHistory.map((h, idx) => (
                              <tr key={idx} className="hover:bg-gray-50 dark:hover:bg-gray-800">
                                  <td className="p-3 text-sm">{new Date(h.date).toLocaleDateString('pt-BR')}</td>
                                  <td className="p-3 text-sm font-medium">{h.supplier_name || 'N/A'}</td>
                                  <td className="p-3 text-sm font-bold text-right text-primary">{h.price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</td>
                              </tr>
                          ))}
                          {priceHistory.length === 0 && (
                              <tr><td colSpan={3} className="p-10 text-center text-gray-400 italic">Sem registros de alteração de preço.</td></tr>
                          )}
                      </tbody>
                  </table>
              </div>
          </div>
      </Modal>

      <Modal isOpen={isProductModalOpen} onClose={() => setIsProductModalOpen(false)} title={currentProduct?.id ? 'Ficha do Produto' : 'Novo Produto'}>
        <form onSubmit={handleProductSubmit} className="space-y-4">
            <div>
                <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Nome Interno</label>
                <input type="text" name="name" defaultValue={currentProduct?.name || ''} required className={formInputClass} />
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">ID Interno</label>
                    <input type="text" name="id" defaultValue={currentProduct?.id || ''} required disabled={!!currentProduct?.id} className={`${formInputClass} bg-gray-50 dark:bg-gray-900 disabled:text-gray-400`} />
                </div>
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Preço Custo (R$)</label>
                    <input type="number" step="0.01" name="unitPrice" defaultValue={currentProduct?.unit_price ?? ''} required className={`${formInputClass} font-bold text-primary`} />
                </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Qtd Atual</label>
                    <input type="number" step="0.01" name="quantity" defaultValue={currentProduct?.quantity ?? ''} required className={formInputClass} />
                </div>
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Mínimo</label>
                    <input type="number" step="1" name="minStock" defaultValue={currentProduct?.min_stock ?? ''} required className={formInputClass} />
                </div>
            </div>
            <button type="submit" className="w-full py-4 bg-primary text-white font-bold rounded-xl shadow-lg mt-4 transition hover:bg-secondary">Gravar Alterações</button>
        </form>
      </Modal>

      <Modal isOpen={isStockModalOpen} onClose={() => setIsStockModalOpen(false)} title={`Movimentação: ${currentProduct?.name}`}>
          <div className="space-y-4">
              <div className="flex justify-between p-4 bg-gray-50 dark:bg-gray-700 rounded-xl border border-gray-100 dark:border-gray-600">
                  <span className="text-gray-500 dark:text-gray-400">Estoque Atual</span>
                  <span className="font-bold text-lg">{currentProduct?.quantity}</span>
              </div>
              <div>
                  <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Quantidade para {stockAction === 'in' ? 'Entrada' : 'Saída'}</label>
                  <input type="number" value={stockQuantity} onChange={e => setStockQuantity(e.target.value)} min="0.01" step="0.01" className={formInputClass} />
              </div>
              {stockAction === 'out' && (
                  <div className="space-y-4">
                    <div>
                        <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Funcionário Responsável</label>
                        <select value={stockEmployeeId} onChange={e => setStockEmployeeId(e.target.value)} className={formInputClass}>
                            <option value="">Selecione...</option>
                            {employees.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
                        </select>
                    </div>
                    <div>
                        <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Ordem de Serviço (Opcional)</label>
                        <select value={stockWorkOrderId} onChange={e => setStockWorkOrderId(e.target.value)} className={formInputClass}>
                            <option value="">Nenhuma / Uso Geral</option>
                            {workOrders.map(wo => <option key={wo.id} value={wo.id}>{wo.title}</option>)}
                        </select>
                    </div>
                  </div>
              )}
              <button onClick={handleStockAction} className={`w-full py-4 rounded-xl font-bold text-white shadow-lg transition ${stockAction === 'in' ? 'bg-green-600 hover:bg-green-700' : 'bg-amber-600 hover:bg-amber-700'}`}>
                  Confirmar {stockAction === 'in' ? 'Entrada' : 'Saída'}
              </button>
          </div>
      </Modal>

      {currentProduct && (
        <QRCodeModal isOpen={isQrModalOpen} onClose={() => setIsQrModalOpen(false)} title={`QR Code: ${currentProduct.name}`} data={currentProduct.id} />
      )}

      <QRCodeScannerModal isOpen={isScannerOpen} onClose={() => setIsScannerOpen(false)} onScan={(data) => { setSearchTerm(data); addToast(`Produto ${data} localizado`, 'success'); }} addToast={addToast} />

    </div>
  );
};

import React, { useState, useMemo, FormEvent, useEffect, useCallback } from 'react';
import { Product, Employee, ToastMessage, User, WorkOrder, PriceHistory, ParsedNFe, NFeProduct } from '../types';
import { Table, SortConfig } from './shared/Table';
import { Modal } from './shared/Modal';
import { useSupabase } from '../contexts/SupabaseContext';
import { QRCodeModal } from './shared/QRCodeModal';
import { QRCodeScannerModal } from './shared/QRCodeScannerModal';
import { parseNFeXML, cleanName } from '../services/nfeParser';
import { parseFiscalDocument } from '../services/geminiService';

interface StockControlProps {
  addToast: (message: string, type: ToastMessage['type']) => void;
  showConfirmation: (message: string, onConfirm: () => void) => void;
  addActivityLog: (action: string) => void;
  currentUser: User;
}

export const StockControl: React.FC<StockControlProps> = ({ 
    addToast, showConfirmation, addActivityLog
}) => {
  const supabase = useSupabase();
  const [products, setProducts] = useState<Product[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [workOrders, setWorkOrders] = useState<WorkOrder[]>([]);
  const [priceHistory, setPriceHistory] = useState<PriceHistory[]>([]);
  const [isProcessingIA, setIsProcessingIA] = useState(false);

  // Estados para Revisão de Importação
  const [pendingImport, setPendingImport] = useState<ParsedNFe | null>(null);
  const [mappings, setMappings] = useState<Record<number, string | 'NEW'>>({});

  const fetchData = useCallback(async () => {
    const [p, e, wo] = await Promise.all([
      supabase.from('products').select('*').order('name'),
      supabase.from('employees').select('*'),
      supabase.from('work_orders').select('*'),
    ]);
    if (p.data) setProducts(p.data);
    if (e.data) setEmployees(e.data);
    if (wo.data) setWorkOrders(wo.data as unknown as WorkOrder[]);
  }, [supabase]);

  useEffect(() => {
    fetchData();
    const channel = supabase.channel('products-realtime')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'products' }, () => fetchData())
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [supabase, fetchData]);

  const [isProductModalOpen, setIsProductModalOpen] = useState(false);
  const [isStockModalOpen, setIsStockModalOpen] = useState(false);
  const [isScannerOpen, setIsScannerOpen] = useState(false);
  const [isQrModalOpen, setIsQrModalOpen] = useState(false);
  const [isPriceHistoryModalOpen, setIsPriceHistoryModalOpen] = useState(false);

  const [currentProduct, setCurrentProduct] = useState<Product | null>(null);
  const [stockAction, setStockAction] = useState<'in' | 'out'>('in');
  const [stockQuantity, setStockQuantity] = useState<number | string>(1);
  const [stockEmployeeId, setStockEmployeeId] = useState<string>('');
  const [stockWorkOrderId, setStockWorkOrderId] = useState<string>('');

  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<SortConfig<Product>>(null);

  const filteredProducts = useMemo(() => {
    return products.filter(p =>
      p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      p.id.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [products, searchTerm]);

  const requestSort = (key: keyof Product) => {
    let direction: 'ascending' | 'descending' = 'ascending';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'ascending') {
      direction = 'descending';
    }
    setSortConfig({ key, direction });
  };

  const sortedProducts = useMemo(() => {
    let sortableItems = [...filteredProducts];
    if (sortConfig !== null) {
      sortableItems.sort((a, b) => {
        const valA = a[sortConfig.key] || '';
        const valB = b[sortConfig.key] || '';
        if (valA < valB) return sortConfig.direction === 'ascending' ? -1 : 1;
        if (valA > valB) return sortConfig.direction === 'ascending' ? 1 : -1;
        return 0;
      });
    }
    return sortableItems;
  }, [filteredProducts, sortConfig]);

  // Lógica de mapeamento inteligente na abertura do modal de revisão
  const openReviewModal = (parsed: ParsedNFe) => {
      const initialMappings: Record<number, string | 'NEW'> = {};

      parsed.products.forEach((p, index) => {
          // 1. Tenta por ID exato
          const matchById = products.find(existing => existing.id === p.code);
          if (matchById) {
              initialMappings[index] = matchById.id;
              return;
          }

          // 2. Tenta por Nome exato (limpo)
          const cleanNfeName = cleanName(p.name).toLowerCase();
          const matchByName = products.find(existing => cleanName(existing.name).toLowerCase() === cleanNfeName);
          if (matchByName) {
              initialMappings[index] = matchByName.id;
              return;
          }

          // 3. Senão, marca como NOVO por padrão
          initialMappings[index] = 'NEW';
      });

      setMappings(initialMappings);
      setPendingImport(parsed);
  };

  const confirmFinalImport = async () => {
      if (!pendingImport) return;

      setIsProcessingIA(true);
      try {
          // 0. Verificar/Cadastrar Fornecedor automaticamente
          const { data: existingSupplier } = await supabase
              .from('suppliers')
              .select('id')
              .eq('cnpj', pendingImport.supplier.cnpj)
              .maybeSingle();

          if (!existingSupplier) {
              const { error: supplierError } = await supabase.from('suppliers').insert({
                  name: pendingImport.supplier.name,
                  cnpj: pendingImport.supplier.cnpj,
                  contact: 'Cadastrado via Importação'
              });

              if (supplierError) {
                  console.warn("Erro ao cadastrar fornecedor novo:", supplierError.message);
                  // Não barramos a importação por isso, apenas logamos
              } else {
                  addActivityLog(`cadastrou automaticamente o fornecedor ${pendingImport.supplier.name} via importação.`);
              }
          }

          // 1. Registrar a Nota Fiscal
          const { error: nfError } = await supabase.from('nfs').insert({
              supplier: { ...pendingImport.supplier, access_key: pendingImport.access_key || null } as any,
              products: pendingImport.products as any,
              total_value: pendingImport.total_value,
              import_date: new Date().toISOString()
          });

          if (nfError) throw new Error(`Erro ao salvar NF: ${nfError.message}`);

          for (let i = 0; i < pendingImport.products.length; i++) {
              const p = pendingImport.products[i];
              const mappingId = mappings[i];

              let targetId = p.code;
              let isNew = true;

              if (mappingId && mappingId !== 'NEW') {
                  targetId = mappingId;
                  isNew = false;
              }

              const { data: existing } = await supabase.from('products').select('*').eq('id', targetId).maybeSingle();

              // Gravar Histórico
              if (!existing || existing.unit_price !== p.unit_price) {
                  await supabase.from('price_history').insert({
                      product_id: targetId,
                      price: p.unit_price,
                      date: new Date().toISOString(),
                      supplier_name: pendingImport.supplier.name
                  });
              }

              if (existing) {
                  await supabase.from('products').update({ 
                      quantity: existing.quantity + p.quantity,
                      unit_price: p.unit_price 
                  }).eq('id', targetId);
              } else {
                  await supabase.from('products').insert({
                      id: targetId,
                      name: p.name,
                      quantity: p.quantity,
                      unit_price: p.unit_price,
                      min_stock: 0
                  });
              }

              await supabase.from('stock_movements').insert({
                  product_id: targetId,
                  product_name: p.name,
                  type: 'in',
                  quantity: p.quantity,
                  date: new Date().toISOString(),
                  reason: `Importação: ${pendingImport.supplier.name}`
              });
          }

          addToast('Importação concluída com sucesso!', 'success');
          addActivityLog(`importou documento de ${pendingImport.supplier.name} com revisão.`);
          setPendingImport(null);
          await fetchData();
      } catch (err: any) {
          addToast(err.message, 'error');
      } finally {
          setIsProcessingIA(false);
      }
  };

  const handleImportXML = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      try {
        const xml = event.target?.result as string;
        const parsed = await parseNFeXML(xml);
        openReviewModal(parsed);
      } catch (err: any) {
        addToast(`Erro ao processar XML: ${err.message}`, 'error');
      }
    };
    reader.readAsText(file);
    e.target.value = ''; 
  };

  const handleImportCupom = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      setIsProcessingIA(true);
      addToast("Aguarde, a IA está analisando o cupom...", "info");

      const reader = new FileReader();
      reader.onload = async (event) => {
          try {
              const base64 = event.target?.result as string;
              const parsed = await parseFiscalDocument(base64, file.type);
              openReviewModal(parsed);
          } catch (err: any) {
              addToast(err.message || "Erro ao processar cupom com IA.", "error");
          } finally {
              setIsProcessingIA(false);
          }
      };
      reader.readAsDataURL(file);
      e.target.value = '';
  };

  const handleProductSubmit = async (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const name = formData.get('name') as string;
    const unit_price = parseFloat(formData.get('unitPrice') as string);
    const quantity = parseFloat(formData.get('quantity') as string);
    const min_stock = parseFloat(formData.get('minStock') as string);

    if (currentProduct?.id) {
      if (currentProduct.unit_price !== unit_price) {
          await supabase.from('price_history').insert({
              product_id: currentProduct.id,
              price: unit_price,
              date: new Date().toISOString(),
              supplier_name: 'Alteração Manual'
          });
      }

      const { error } = await supabase.from('products').update({
        name, unit_price, quantity, min_stock
      }).eq('id', currentProduct.id);

      if (error) addToast(`Erro ao atualizar: ${error.message}`, 'error');
      else {
        addToast('Produto atualizado!', 'success');
        addActivityLog(`atualizou o produto ${name}`);
        await fetchData();
        setIsProductModalOpen(false);
      }
    } else {
      const id = formData.get('id') as string;
      const { error } = await supabase.from('products').insert({
        id, name, unit_price, quantity, min_stock
      });

      if (error) addToast(`Erro ao cadastrar: ${error.message}`, 'error');
      else {
        await supabase.from('price_history').insert({
            product_id: id,
            price: unit_price,
            date: new Date().toISOString(),
            supplier_name: 'Cadastro Inicial'
        });
        addToast('Produto cadastrado!', 'success');
        addActivityLog(`cadastrou o produto ${name}`);
        await fetchData();
        setIsProductModalOpen(false);
      }
    }
  };

  const handleStockAction = async () => {
    if (!currentProduct) return;
    const qty = parseFloat(stockQuantity as string);
    const newQty = stockAction === 'in' ? currentProduct.quantity + qty : currentProduct.quantity - qty;

    if (newQty < 0) {
      addToast('Erro: Estoque insuficiente.', 'error');
      return;
    }

    const { error } = await supabase.from('products').update({ quantity: newQty }).eq('id', currentProduct.id);
    if (error) {
      addToast(`Erro ao movimentar: ${error.message}`, 'error');
      return;
    }

    const employee = employees.find(e => e.id === stockEmployeeId);
    const movement = {
      product_id: currentProduct.id,
      product_name: currentProduct.name,
      type: stockAction,
      quantity: qty,
      date: new Date().toISOString(),
      employee_id: stockEmployeeId || null,
      employee_name: employee?.name || null,
      work_order_id: stockWorkOrderId || null,
      reason: stockAction === 'in' ? 'Entrada manual' : 'Saída manual',
    };

    await supabase.from('stock_movements').insert(movement);
    addToast('Estoque atualizado!', 'success');
    addActivityLog(`${stockAction === 'in' ? 'entrada' : 'saída'} de ${qty}x ${currentProduct.name}`);
    await fetchData();
    setIsStockModalOpen(false);
  };

  const handleDelete = (product: Product) => {
    showConfirmation(`Deseja excluir o produto ${product.name}?`, async () => {
      const { error } = await supabase.from('products').delete().eq('id', product.id);
      if (error) addToast(`Erro ao excluir: ${error.message}`, 'error');
      else {
        addToast('Produto excluído!', 'success');
        addActivityLog(`excluiu o produto ${product.name}`);
        await fetchData();
      }
    });
  };

  const viewPriceHistory = async (product: Product) => {
      setCurrentProduct(product);
      const { data } = await supabase
        .from('price_history')
        .select('*')
        .eq('product_id', product.id)
        .order('date', { ascending: false });

      if (data) setPriceHistory(data as unknown as PriceHistory[]);
      setIsPriceHistoryModalOpen(true);
  };

  const columns = [
    { header: 'ID', accessor: 'id' as const, sortable: true },
    { header: 'Nome', accessor: 'name' as const, sortable: true },
    { header: 'Qtd', accessor: 'quantity' as const, sortable: true },
    { header: 'Preço', accessor: (item: Product) => item.unit_price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }), sortable: true, sortKey: 'unit_price' as const },
    { header: 'Mínimo', accessor: 'min_stock' as const, sortable: true },
  ];

  const formInputClass = "w-full p-3 border rounded-xl dark:bg-gray-800 dark:border-gray-700 dark:text-gray-200";

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-800 dark:text-gray-200">Controle de Estoque</h2>
          <p className="text-gray-500 dark:text-gray-400">Gerencie seus produtos de consumo e insumos.</p>
        </div>
        <div className="flex flex-wrap gap-2">
            <label className={`bg-amber-600 text-white px-4 py-2 rounded-lg hover:bg-amber-700 transition flex items-center cursor-pointer shadow-lg ${isProcessingIA ? 'opacity-50 pointer-events-none' : ''}`}>
                {isProcessingIA ? (
                    <svg className="animate-spin h-5 w-5 mr-2" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                ) : (
                    <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"></path></svg>
                )}
                Importar Cupom (IA)
                <input type="file" accept="image/*,.pdf" className="hidden" onChange={handleImportCupom} disabled={isProcessingIA} />
            </label>
            <label className="bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition flex items-center cursor-pointer shadow-lg">
                <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
                XML NFe
                <input type="file" accept=".xml" className="hidden" onChange={handleImportXML} />
            </label>
            <button onClick={() => setIsScannerOpen(true)} className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition flex items-center shadow-lg">
                <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg>
                Escanear
            </button>
            <button onClick={() => { setCurrentProduct(null); setIsProductModalOpen(true); }} className="bg-primary text-white px-4 py-2 rounded-lg hover:bg-secondary transition shadow-lg">
                Novo Produto
            </button>
        </div>
      </div>

      <div className="relative">
        <input
          type="text"
          placeholder="Buscar por nome ou ID..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="w-full pl-10 pr-4 py-2 border rounded-lg dark:bg-gray-800 dark:border-gray-600 dark:text-gray-200"
        />
        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
          <svg className="h-5 w-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
        </div>
      </div>

      <Table<Product>
        columns={columns}
        data={sortedProducts}
        sortConfig={sortConfig}
        requestSort={requestSort}
        actions={(product) => (
          <div className="flex space-x-2">
            <button onClick={() => { setCurrentProduct(product); setStockAction('in'); setStockQuantity(1); setIsStockModalOpen(true); }} title="Entrada" className="text-green-600 hover:bg-green-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"></path></svg></button>
            <button onClick={() => { setCurrentProduct(product); setStockAction('out'); setStockQuantity(1); setIsStockModalOpen(true); }} title="Saída" className="text-amber-600 hover:bg-amber-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 12H4"></path></svg></button>
            <button onClick={() => viewPriceHistory(product)} title="Histórico de Preço" className="text-purple-600 hover:bg-purple-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6"></path></svg></button>
            <button onClick={() => { setCurrentProduct(product); setIsQrModalOpen(true); }} title="QR Code" className="text-gray-600 hover:bg-gray-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg></button>
            <button onClick={() => { setCurrentProduct(product); setIsProductModalOpen(true); }} title="Editar" className="text-indigo-600 hover:text-indigo-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg></button>
            <button onClick={() => handleDelete(product)} title="Excluir" className="text-red-600 hover:bg-red-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg></button>
          </div>
        )}
      />

      {/* MODAL DE REVISÃO DE IMPORTAÇÃO */}
      <Modal 
        isOpen={!!pendingImport} 
        onClose={() => setPendingImport(null)} 
        title={`Revisão de Importação: ${pendingImport?.supplier.name}`}
      >
          <div className="space-y-6">
              <p className="text-sm text-gray-500">
                  Verifique os itens abaixo. O sistema sugeriu vínculos baseados no nome ou código. 
                  Você pode escolher "Cadastrar como NOVO" ou selecionar um produto já existente para evitar duplicidade.
              </p>

              <div className="max-h-[500px] overflow-y-auto space-y-4 pr-2">
                  {pendingImport?.products.map((item, idx) => (
                      <div key={idx} className="p-4 border dark:border-gray-700 rounded-xl bg-gray-50 dark:bg-gray-800/50 space-y-3">
                          <div className="flex justify-between items-start">
                              <div className="flex-1">
                                  <h4 className="text-sm font-bold text-gray-800 dark:text-gray-100 uppercase">{item.name}</h4>
                                  <p className="text-[10px] text-gray-500 font-mono">Cód. Nota: {item.code} | Vlr: {item.unit_price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</p>
                              </div>
                              <div className="text-right ml-4">
                                  <span className="text-sm font-bold text-primary">+{item.quantity} un</span>
                              </div>
                          </div>

                          <div>
                              <label className="text-[10px] font-bold uppercase text-gray-400 mb-1 block">Vincular ao Produto:</label>
                              <select 
                                  value={mappings[idx]} 
                                  onChange={e => setMappings(prev => ({...prev, [idx]: e.target.value}))}
                                  className="w-full p-2 text-xs border rounded-lg dark:bg-gray-700 dark:border-gray-600"
                              >
                                  <option value="NEW" className="font-bold text-emerald-600 italic">✨ CADASTRAR COMO NOVO ITEM</option>
                                  <optgroup label="PRODUTOS EM ESTOQUE">
                                      {products.map(p => (
                                          <option key={p.id} value={p.id}>
                                              {p.name} (Saldo: {p.quantity})
                                          </option>
                                      ))}
                                  </optgroup>
                              </select>
                          </div>
                      </div>
                  ))}
              </div>

              <div className="flex flex-col space-y-2">
                  <button 
                      onClick={confirmFinalImport}
                      disabled={isProcessingIA}
                      className="w-full py-4 bg-primary text-white font-bold rounded-xl shadow-lg hover:bg-secondary transition disabled:opacity-50"
                  >
                      {isProcessingIA ? 'Processando...' : 'Confirmar e Alimentar Estoque'}
                  </button>
                  <button onClick={() => setPendingImport(null)} className="w-full py-2 text-sm text-gray-500 hover:text-red-500 transition">Cancelar Importação</button>
              </div>
          </div>
      </Modal>

      {/* Histórico de Preços */}
      <Modal isOpen={isPriceHistoryModalOpen} onClose={() => setIsPriceHistoryModalOpen(false)} title={`Histórico de Preços: ${currentProduct?.name}`}>
          <div className="space-y-4">
              <div className="max-h-[400px] overflow-y-auto">
                  <table className="w-full text-left">
                      <thead className="bg-gray-50 dark:bg-gray-700 sticky top-0">
                          <tr>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500">Data</th>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500">Fornecedor/Origem</th>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500 text-right">Preço</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y dark:divide-gray-700">
                          {priceHistory.map((h, idx) => (
                              <tr key={idx} className="hover:bg-gray-50 dark:hover:bg-gray-800">
                                  <td className="p-3 text-sm">{new Date(h.date).toLocaleDateString('pt-BR')}</td>
                                  <td className="p-3 text-sm font-medium">{h.supplier_name || 'N/A'}</td>
                                  <td className="p-3 text-sm font-bold text-right text-primary">{h.price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</td>
                              </tr>
                          ))}
                          {priceHistory.length === 0 && (
                              <tr><td colSpan={3} className="p-10 text-center text-gray-400 italic">Sem registros de alteração de preço.</td></tr>
                          )}
                      </tbody>
                  </table>
              </div>
          </div>
      </Modal>

      <Modal isOpen={isProductModalOpen} onClose={() => setIsProductModalOpen(false)} title={currentProduct?.id ? 'Ficha do Produto' : 'Novo Produto'}>
        <form onSubmit={handleProductSubmit} className="space-y-4">
            <div>
                <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Nome Interno</label>
                <input type="text" name="name" defaultValue={currentProduct?.name || ''} required className={formInputClass} />
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">ID Interno</label>
                    <input type="text" name="id" defaultValue={currentProduct?.id || ''} required disabled={!!currentProduct?.id} className={`${formInputClass} bg-gray-50 dark:bg-gray-900 disabled:text-gray-400`} />
                </div>
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Preço Custo (R$)</label>
                    <input type="number" step="0.01" name="unitPrice" defaultValue={currentProduct?.unit_price ?? ''} required className={`${formInputClass} font-bold text-primary`} />
                </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Qtd Atual</label>
                    <input type="number" step="0.01" name="quantity" defaultValue={currentProduct?.quantity ?? ''} required className={formInputClass} />
                </div>
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Mínimo</label>
                    <input type="number" step="1" name="minStock" defaultValue={currentProduct?.min_stock ?? ''} required className={formInputClass} />
                </div>
            </div>
            <button type="submit" className="w-full py-4 bg-primary text-white font-bold rounded-xl shadow-lg mt-4 transition hover:bg-secondary">Gravar Alterações</button>
        </form>
      </Modal>

      <Modal isOpen={isStockModalOpen} onClose={() => setIsStockModalOpen(false)} title={`Movimentação: ${currentProduct?.name}`}>
          <div className="space-y-4">
              <div className="flex justify-between p-4 bg-gray-50 dark:bg-gray-700 rounded-xl border border-gray-100 dark:border-gray-600">
                  <span className="text-gray-500 dark:text-gray-400">Estoque Atual</span>
                  <span className="font-bold text-lg">{currentProduct?.quantity}</span>
              </div>
              <div>
                  <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Quantidade para {stockAction === 'in' ? 'Entrada' : 'Saída'}</label>
                  <input type="number" value={stockQuantity} onChange={e => setStockQuantity(e.target.value)} min="0.01" step="0.01" className={formInputClass} />
              </div>
              {stockAction === 'out' && (
                  <div className="space-y-4">
                    <div>
                        <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Funcionário Responsável</label>
                        <select value={stockEmployeeId} onChange={e => setStockEmployeeId(e.target.value)} className={formInputClass}>
                            <option value="">Selecione...</option>
                            {employees.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
                        </select>
                    </div>
                    <div>
                        <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Ordem de Serviço (Opcional)</label>
                        <select value={stockWorkOrderId} onChange={e => setStockWorkOrderId(e.target.value)} className={formInputClass}>
                            <option value="">Nenhuma / Uso Geral</option>
                            {workOrders.map(wo => <option key={wo.id} value={wo.id}>{wo.title}</option>)}
                        </select>
                    </div>
                  </div>
              )}
              <button onClick={handleStockAction} className={`w-full py-4 rounded-xl font-bold text-white shadow-lg transition ${stockAction === 'in' ? 'bg-green-600 hover:bg-green-700' : 'bg-amber-600 hover:bg-amber-700'}`}>
                  Confirmar {stockAction === 'in' ? 'Entrada' : 'Saída'}
              </button>
          </div>
      </Modal>

      {currentProduct && (
        <QRCodeModal isOpen={isQrModalOpen} onClose={() => setIsQrModalOpen(false)} title={`QR Code: ${currentProduct.name}`} data={currentProduct.id} />
      )}

      <QRCodeScannerModal isOpen={isScannerOpen} onClose={() => setIsScannerOpen(false)} onScan={(data) => { setSearchTerm(data); addToast(`Produto ${data} localizado`, 'success'); }} addToast={addToast} />

    </div>
  );
};

import React, { useState, useMemo, FormEvent, useEffect, useCallback } from 'react';
import { Product, Employee, ToastMessage, User, WorkOrder, PriceHistory, ParsedNFe, NFeProduct } from '../types';
import { Table, SortConfig } from './shared/Table';
import { Modal } from './shared/Modal';
import { useSupabase } from '../contexts/SupabaseContext';
import { QRCodeModal } from './shared/QRCodeModal';
import { QRCodeScannerModal } from './shared/QRCodeScannerModal';
import { parseNFeXML, cleanName } from '../services/nfeParser';
import { parseFiscalDocument } from '../services/geminiService';

interface StockControlProps {
  addToast: (message: string, type: ToastMessage['type']) => void;
  showConfirmation: (message: string, onConfirm: () => void) => void;
  addActivityLog: (action: string) => void;
  currentUser: User;
}

export const StockControl: React.FC<StockControlProps> = ({ 
    addToast, showConfirmation, addActivityLog
}) => {
  const supabase = useSupabase();
  const [products, setProducts] = useState<Product[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [workOrders, setWorkOrders] = useState<WorkOrder[]>([]);
  const [priceHistory, setPriceHistory] = useState<PriceHistory[]>([]);
  const [isProcessingIA, setIsProcessingIA] = useState(false);

  // Estados para Seleção e Revisão
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [pendingImport, setPendingImport] = useState<ParsedNFe | null>(null);
  const [mappings, setMappings] = useState<Record<number, string | 'NEW'>>({});

  const fetchData = useCallback(async () => {
    const [p, e, wo] = await Promise.all([
      supabase.from('products').select('*').order('name'),
      supabase.from('employees').select('*'),
      supabase.from('work_orders').select('*'),
    ]);
    if (p.data) setProducts(p.data);
    if (e.data) setEmployees(e.data);
    if (wo.data) setWorkOrders(wo.data as unknown as WorkOrder[]);
  }, [supabase]);

  useEffect(() => {
    fetchData();
    const channel = supabase.channel('products-realtime')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'products' }, () => fetchData())
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [supabase, fetchData]);

  const [isProductModalOpen, setIsProductModalOpen] = useState(false);
  const [isStockModalOpen, setIsStockModalOpen] = useState(false);
  const [isScannerOpen, setIsScannerOpen] = useState(false);
  const [isQrModalOpen, setIsQrModalOpen] = useState(false);
  const [isPriceHistoryModalOpen, setIsPriceHistoryModalOpen] = useState(false);

  const [currentProduct, setCurrentProduct] = useState<Product | null>(null);
  const [stockAction, setStockAction] = useState<'in' | 'out'>('in');
  const [stockQuantity, setStockQuantity] = useState<number | string>(1);
  const [stockEmployeeId, setStockEmployeeId] = useState<string>('');
  const [stockWorkOrderId, setStockWorkOrderId] = useState<string>('');

  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<SortConfig<Product>>(null);

  const filteredProducts = useMemo(() => {
    return products.filter(p =>
      p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      p.id.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [products, searchTerm]);

  const requestSort = (key: keyof Product) => {
    let direction: 'ascending' | 'descending' = 'ascending';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'ascending') {
      direction = 'descending';
    }
    setSortConfig({ key, direction });
  };

  const sortedProducts = useMemo(() => {
    let sortableItems = [...filteredProducts];
    if (sortConfig !== null) {
      sortableItems.sort((a, b) => {
        const valA = a[sortConfig.key] || '';
        const valB = b[sortConfig.key] || '';
        if (valA < valB) return sortConfig.direction === 'ascending' ? -1 : 1;
        if (valA > valB) return sortConfig.direction === 'ascending' ? 1 : -1;
        return 0;
      });
    }
    return sortableItems;
  }, [filteredProducts, sortConfig]);

  const handleBulkDelete = () => {
    if (selectedIds.length === 0) return;

    showConfirmation(`Tem certeza que deseja excluir ${selectedIds.length} produtos selecionados? Esta ação não pode ser desfeita.`, async () => {
        const { error } = await supabase.from('products').delete().in('id', selectedIds);
        if (error) {
            addToast(`Erro ao excluir em massa: ${error.message}`, 'error');
        } else {
            addToast(`${selectedIds.length} produtos excluídos com sucesso!`, 'success');
            addActivityLog(`excluiu em massa ${selectedIds.length} produtos.`);
            setSelectedIds([]);
            await fetchData();
        }
    });
  };

  // Lógica de mapeamento inteligente na abertura do modal de revisão
  const openReviewModal = (parsed: ParsedNFe) => {
      const initialMappings: Record<number, string | 'NEW'> = {};

      parsed.products.forEach((p, index) => {
          const matchById = products.find(existing => existing.id === p.code);
          if (matchById) {
              initialMappings[index] = matchById.id;
              return;
          }
          const cleanNfeName = cleanName(p.name).toLowerCase();
          const matchByName = products.find(existing => cleanName(existing.name).toLowerCase() === cleanNfeName);
          if (matchByName) {
              initialMappings[index] = matchByName.id;
              return;
          }
          initialMappings[index] = 'NEW';
      });

      setMappings(initialMappings);
      setPendingImport(parsed);
  };

  const confirmFinalImport = async () => {
      if (!pendingImport) return;

      setIsProcessingIA(true);
      try {
          const { data: existingSupplier } = await supabase
              .from('suppliers')
              .select('id')
              .eq('cnpj', pendingImport.supplier.cnpj)
              .maybeSingle();

          if (!existingSupplier) {
              await supabase.from('suppliers').insert({
                  name: pendingImport.supplier.name,
                  cnpj: pendingImport.supplier.cnpj,
                  contact: 'Cadastrado via Importação'
              });
              addActivityLog(`cadastrou automaticamente o fornecedor ${pendingImport.supplier.name} via importação.`);
          }

          const { error: nfError } = await supabase.from('nfs').insert({
              supplier: { ...pendingImport.supplier, access_key: pendingImport.access_key || null } as any,
              products: pendingImport.products as any,
              total_value: pendingImport.total_value,
              import_date: new Date().toISOString()
          });

          if (nfError) throw new Error(`Erro ao salvar NF: ${nfError.message}`);

          for (let i = 0; i < pendingImport.products.length; i++) {
              const p = pendingImport.products[i];
              const mappingId = mappings[i];

              let targetId = p.code;
              if (mappingId && mappingId !== 'NEW') {
                  targetId = mappingId;
              }

              const { data: existing } = await supabase.from('products').select('*').eq('id', targetId).maybeSingle();

              if (!existing || existing.unit_price !== p.unit_price) {
                  await supabase.from('price_history').insert({
                      product_id: targetId,
                      price: p.unit_price,
                      date: new Date().toISOString(),
                      supplier_name: pendingImport.supplier.name
                  });
              }

              if (existing) {
                  await supabase.from('products').update({ 
                      quantity: existing.quantity + p.quantity,
                      unit_price: p.unit_price 
                  }).eq('id', targetId);
              } else {
                  await supabase.from('products').insert({
                      id: targetId,
                      name: p.name,
                      quantity: p.quantity,
                      unit_price: p.unit_price,
                      min_stock: 0
                  });
              }

              await supabase.from('stock_movements').insert({
                  product_id: targetId,
                  product_name: p.name,
                  type: 'in',
                  quantity: p.quantity,
                  date: new Date().toISOString(),
                  reason: `Importação: ${pendingImport.supplier.name}`
              });
          }

          addToast('Importação concluída com sucesso!', 'success');
          addActivityLog(`importou documento de ${pendingImport.supplier.name} com revisão.`);
          setPendingImport(null);
          await fetchData();
      } catch (err: any) {
          addToast(err.message, 'error');
      } finally {
          setIsProcessingIA(false);
      }
  };

  const handleImportXML = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (event) => {
      try {
        const xml = event.target?.result as string;
        const parsed = await parseNFeXML(xml);
        openReviewModal(parsed);
      } catch (err: any) {
        addToast(`Erro ao processar XML: ${err.message}`, 'error');
      }
    };
    reader.readAsText(file);
    e.target.value = ''; 
  };

  const handleImportCupom = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      setIsProcessingIA(true);
      addToast("Aguarde, a IA está analisando o cupom...", "info");
      const reader = new FileReader();
      reader.onload = async (event) => {
          try {
              const base64 = event.target?.result as string;
              const parsed = await parseFiscalDocument(base64, file.type);
              openReviewModal(parsed);
          } catch (err: any) {
              addToast(err.message || "Erro ao processar cupom com IA.", "error");
          } finally {
              setIsProcessingIA(false);
          }
      };
      reader.readAsDataURL(file);
      e.target.value = '';
  };

  const handleProductSubmit = async (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const name = formData.get('name') as string;
    const unit_price = parseFloat(formData.get('unitPrice') as string);
    const quantity = parseFloat(formData.get('quantity') as string);
    const min_stock = parseFloat(formData.get('minStock') as string);

    if (currentProduct?.id) {
      if (currentProduct.unit_price !== unit_price) {
          await supabase.from('price_history').insert({
              product_id: currentProduct.id,
              price: unit_price,
              date: new Date().toISOString(),
              supplier_name: 'Alteração Manual'
          });
      }
      const { error } = await supabase.from('products').update({ name, unit_price, quantity, min_stock }).eq('id', currentProduct.id);
      if (error) addToast(`Erro ao atualizar: ${error.message}`, 'error');
      else {
        addToast('Produto atualizado!', 'success');
        addActivityLog(`atualizou o produto ${name}`);
        await fetchData();
        setIsProductModalOpen(false);
      }
    } else {
      const id = formData.get('id') as string;
      const { error } = await supabase.from('products').insert({ id, name, unit_price, quantity, min_stock });
      if (error) addToast(`Erro ao cadastrar: ${error.message}`, 'error');
      else {
        await supabase.from('price_history').insert({ product_id: id, price: unit_price, date: new Date().toISOString(), supplier_name: 'Cadastro Inicial' });
        addToast('Produto cadastrado!', 'success');
        addActivityLog(`cadastrou o produto ${name}`);
        await fetchData();
        setIsProductModalOpen(false);
      }
    }
  };

  const handleStockAction = async () => {
    if (!currentProduct) return;
    const qty = parseFloat(stockQuantity as string);
    const newQty = stockAction === 'in' ? currentProduct.quantity + qty : currentProduct.quantity - qty;
    if (newQty < 0) { addToast('Erro: Estoque insuficiente.', 'error'); return; }
    const { error } = await supabase.from('products').update({ quantity: newQty }).eq('id', currentProduct.id);
    if (error) { addToast(`Erro ao movimentar: ${error.message}`, 'error'); return; }
    const employee = employees.find(e => e.id === stockEmployeeId);
    const movement = {
      product_id: currentProduct.id,
      product_name: currentProduct.name,
      type: stockAction,
      quantity: qty,
      date: new Date().toISOString(),
      employee_id: stockEmployeeId || null,
      employee_name: employee?.name || null,
      work_order_id: stockWorkOrderId || null,
      reason: stockAction === 'in' ? 'Entrada manual' : 'Saída manual',
    };
    await supabase.from('stock_movements').insert(movement);
    addToast('Estoque atualizado!', 'success');
    addActivityLog(`${stockAction === 'in' ? 'entrada' : 'saída'} de ${qty}x ${currentProduct.name}`);
    await fetchData();
    setIsStockModalOpen(false);
  };

  const handleDelete = (product: Product) => {
    showConfirmation(`Deseja excluir o produto ${product.name}?`, async () => {
      const { error } = await supabase.from('products').delete().eq('id', product.id);
      if (error) addToast(`Erro ao excluir: ${error.message}`, 'error');
      else {
        addToast('Produto excluído!', 'success');
        addActivityLog(`excluiu o produto ${product.name}`);
        await fetchData();
      }
    });
  };

  const viewPriceHistory = async (product: Product) => {
      setCurrentProduct(product);
      const { data } = await supabase.from('price_history').select('*').eq('product_id', product.id).order('date', { ascending: false });
      if (data) setPriceHistory(data as unknown as PriceHistory[]);
      setIsPriceHistoryModalOpen(true);
  };

  const columns = [
    { header: 'ID', accessor: 'id' as const, sortable: true },
    { header: 'Nome', accessor: 'name' as const, sortable: true },
    { header: 'Qtd', accessor: 'quantity' as const, sortable: true },
    { header: 'Preço', accessor: (item: Product) => item.unit_price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }), sortable: true, sortKey: 'unit_price' as const },
    { header: 'Mínimo', accessor: 'min_stock' as const, sortable: true },
  ];

  const formInputClass = "w-full p-3 border rounded-xl dark:bg-gray-800 dark:border-gray-700 dark:text-gray-200";

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-800 dark:text-gray-200">Controle de Estoque</h2>
          <p className="text-gray-500 dark:text-gray-400">Gerencie seus produtos de consumo e insumos.</p>
        </div>
        <div className="flex flex-wrap gap-2">
            {selectedIds.length > 0 && (
                <button 
                    onClick={handleBulkDelete}
                    className="bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700 transition flex items-center shadow-lg animate-pulse"
                >
                    <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                    Excluir ({selectedIds.length})
                </button>
            )}
            <label className={`bg-amber-600 text-white px-4 py-2 rounded-lg hover:bg-amber-700 transition flex items-center cursor-pointer shadow-lg ${isProcessingIA ? 'opacity-50 pointer-events-none' : ''}`}>
                {isProcessingIA ? (
                    <svg className="animate-spin h-5 w-5 mr-2" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                ) : (
                    <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"></path></svg>
                )}
                Importar Cupom (IA)
                <input type="file" accept="image/*,.pdf" className="hidden" onChange={handleImportCupom} disabled={isProcessingIA} />
            </label>
            <label className="bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition flex items-center cursor-pointer shadow-lg">
                <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
                XML NFe
                <input type="file" accept=".xml" className="hidden" onChange={handleImportXML} />
            </label>
            <button onClick={() => setIsScannerOpen(true)} className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition flex items-center shadow-lg">
                <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg>
                Escanear
            </button>
            <button onClick={() => { setCurrentProduct(null); setIsProductModalOpen(true); }} className="bg-primary text-white px-4 py-2 rounded-lg hover:bg-secondary transition shadow-lg">
                Novo Produto
            </button>
        </div>
      </div>

      <div className="relative">
        <input
          type="text"
          placeholder="Buscar por nome ou ID..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="w-full pl-10 pr-4 py-2 border rounded-lg dark:bg-gray-800 dark:border-gray-600 dark:text-gray-200"
        />
        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
          <svg className="h-5 w-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
        </div>
      </div>

      <Table<Product>
        columns={columns}
        data={sortedProducts}
        sortConfig={sortConfig}
        requestSort={requestSort}
        selectedItems={selectedIds}
        setSelectedItems={setSelectedIds}
        actions={(product) => (
          <div className="flex space-x-2">
            <button onClick={() => { setCurrentProduct(product); setStockAction('in'); setStockQuantity(1); setIsStockModalOpen(true); }} title="Entrada" className="text-green-600 hover:bg-green-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"></path></svg></button>
            <button onClick={() => { setCurrentProduct(product); setStockAction('out'); setStockQuantity(1); setIsStockModalOpen(true); }} title="Saída" className="text-amber-600 hover:bg-amber-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 12H4"></path></svg></button>
            <button onClick={() => viewPriceHistory(product)} title="Histórico de Preço" className="text-purple-600 hover:bg-purple-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6"></path></svg></button>
            <button onClick={() => { setCurrentProduct(product); setIsQrModalOpen(true); }} title="QR Code" className="text-gray-600 hover:bg-gray-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg></button>
            <button onClick={() => { setCurrentProduct(product); setIsProductModalOpen(true); }} title="Editar" className="text-indigo-600 hover:text-indigo-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg></button>
            <button onClick={() => handleDelete(product)} title="Excluir" className="text-red-600 hover:bg-red-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg></button>
          </div>
        )}
      />

      {/* MODAL DE REVISÃO DE IMPORTAÇÃO */}
      <Modal isOpen={!!pendingImport} onClose={() => setPendingImport(null)} title={`Revisão de Importação: ${pendingImport?.supplier.name}`}>
          <div className="space-y-6">
              <p className="text-sm text-gray-500">Verifique os itens abaixo e vincule-os corretamente.</p>
              <div className="max-h-[500px] overflow-y-auto space-y-4 pr-2">
                  {pendingImport?.products.map((item, idx) => (
                      <div key={idx} className="p-4 border dark:border-gray-700 rounded-xl bg-gray-50 dark:bg-gray-800/50 space-y-3">
                          <div className="flex justify-between items-start">
                              <div className="flex-1">
                                  <h4 className="text-sm font-bold text-gray-800 dark:text-gray-100 uppercase">{item.name}</h4>
                                  <p className="text-[10px] text-gray-500 font-mono">Cód. Nota: {item.code} | Vlr: {item.unit_price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</p>
                              </div>
                              <div className="text-right ml-4"><span className="text-sm font-bold text-primary">+{item.quantity} un</span></div>
                          </div>
                          <div>
                              <label className="text-[10px] font-bold uppercase text-gray-400 mb-1 block">Vincular ao Produto:</label>
                              <select value={mappings[idx]} onChange={e => setMappings(prev => ({...prev, [idx]: e.target.value}))} className="w-full p-2 text-xs border rounded-lg dark:bg-gray-700 dark:border-gray-600">
                                  <option value="NEW">✨ CADASTRAR COMO NOVO ITEM</option>
                                  <optgroup label="PRODUTOS EM ESTOQUE">
                                      {products.map(p => (<option key={p.id} value={p.id}>{p.name} (Saldo: {p.quantity})</option>))}
                                  </optgroup>
                              </select>
                          </div>
                      </div>
                  ))}
              </div>
              <div className="flex flex-col space-y-2">
                  <button onClick={confirmFinalImport} disabled={isProcessingIA} className="w-full py-4 bg-primary text-white font-bold rounded-xl shadow-lg hover:bg-secondary transition disabled:opacity-50">{isProcessingIA ? 'Processando...' : 'Confirmar e Alimentar Estoque'}</button>
                  <button onClick={() => setPendingImport(null)} className="w-full py-2 text-sm text-gray-500 hover:text-red-500 transition">Cancelar Importação</button>
              </div>
          </div>
      </Modal>

      {/* Outros Modais (Preço, Cadastro, Movimentação, etc) mantidos como no arquivo original */}
      <Modal isOpen={isPriceHistoryModalOpen} onClose={() => setIsPriceHistoryModalOpen(false)} title={`Histórico de Preços: ${currentProduct?.name}`}>
          <div className="space-y-4">
              <div className="max-h-[400px] overflow-y-auto">
                  <table className="w-full text-left">
                      <thead className="bg-gray-50 dark:bg-gray-700 sticky top-0">
                          <tr>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500">Data</th>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500">Fornecedor/Origem</th>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500 text-right">Preço</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y dark:divide-gray-700">
                          {priceHistory.map((h, idx) => (
                              <tr key={idx} className="hover:bg-gray-50 dark:hover:bg-gray-800">
                                  <td className="p-3 text-sm">{new Date(h.date).toLocaleDateString('pt-BR')}</td>
                                  <td className="p-3 text-sm font-medium">{h.supplier_name || 'N/A'}</td>
                                  <td className="p-3 text-sm font-bold text-right text-primary">{h.price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</td>
                              </tr>
                          ))}
                      </tbody>
                  </table>
              </div>
          </div>
      </Modal>

      <Modal isOpen={isProductModalOpen} onClose={() => setIsProductModalOpen(false)} title={currentProduct?.id ? 'Ficha do Produto' : 'Novo Produto'}>
        <form onSubmit={handleProductSubmit} className="space-y-4">
            <div>
                <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Nome Interno</label>
                <input type="text" name="name" defaultValue={currentProduct?.name || ''} required className={formInputClass} />
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">ID Interno</label>
                    <input type="text" name="id" defaultValue={currentProduct?.id || ''} required disabled={!!currentProduct?.id} className={`${formInputClass} bg-gray-50 dark:bg-gray-900 disabled:text-gray-400`} />
                </div>
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Preço Custo (R$)</label>
                    <input type="number" step="0.01" name="unitPrice" defaultValue={currentProduct?.unit_price ?? ''} required className={`${formInputClass} font-bold text-primary`} />
                </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Qtd Atual</label>
                    <input type="number" step="0.01" name="quantity" defaultValue={currentProduct?.quantity ?? ''} required className={formInputClass} />
                </div>
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Mínimo</label>
                    <input type="number" step="1" name="minStock" defaultValue={currentProduct?.min_stock ?? ''} required className={formInputClass} />
                </div>
            </div>
            <button type="submit" className="w-full py-4 bg-primary text-white font-bold rounded-xl shadow-lg mt-4 transition hover:bg-secondary">Gravar Alterações</button>
        </form>
      </Modal>

      <Modal isOpen={isStockModalOpen} onClose={() => setIsStockModalOpen(false)} title={`Movimentação: ${currentProduct?.name}`}>
          <div className="space-y-4">
              <div className="flex justify-between p-4 bg-gray-50 dark:bg-gray-700 rounded-xl border border-gray-100 dark:border-gray-600">
                  <span className="text-gray-500 dark:text-gray-400">Estoque Atual</span>
                  <span className="font-bold text-lg">{currentProduct?.quantity}</span>
              </div>
              <div>
                  <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Quantidade para {stockAction === 'in' ? 'Entrada' : 'Saída'}</label>
                  <input type="number" value={stockQuantity} onChange={e => setStockQuantity(e.target.value)} min="0.01" step="0.01" className={formInputClass} />
              </div>
              {stockAction === 'out' && (
                  <div className="space-y-4">
                    <div>
                        <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Funcionário Responsável</label>
                        <select value={stockEmployeeId} onChange={e => setStockEmployeeId(e.target.value)} className={formInputClass}>
                            <option value="">Selecione...</option>
                            {employees.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
                        </select>
                    </div>
                  </div>
              )}
              <button onClick={handleStockAction} className={`w-full py-4 rounded-xl font-bold text-white shadow-lg transition ${stockAction === 'in' ? 'bg-green-600 hover:bg-green-700' : 'bg-amber-600 hover:bg-amber-700'}`}>
                  Confirmar {stockAction === 'in' ? 'Entrada' : 'Saída'}
              </button>
          </div>
      </Modal>

      {currentProduct && (
        <QRCodeModal isOpen={isQrModalOpen} onClose={() => setIsQrModalOpen(false)} title={`QR Code: ${currentProduct.name}`} data={currentProduct.id} />
      )}
      <QRCodeScannerModal isOpen={isScannerOpen} onClose={() => setIsScannerOpen(false)} onScan={(data) => { setSearchTerm(data); addToast(`Produto ${data} localizado`, 'success'); }} addToast={addToast} />
    </div>
  );
};

import React, { useState, useMemo, FormEvent, useEffect, useCallback } from 'react';
import { PurchaseOrder, Supplier, Product, ToastMessage, User, StockMovement } from '../types';
import { Table, SortConfig } from './shared/Table';
import { Modal } from './shared/Modal';
import { useSupabase } from '../contexts/SupabaseContext';

interface PurchaseOrdersProps {
  addToast: (message: string, type: ToastMessage['type']) => void;
  showConfirmation: (message: string, onConfirm: () => void) => void;
  addActivityLog: (action: string) => void;
  currentUser: User;
}

export const PurchaseOrders: React.FC<PurchaseOrdersProps> = ({
  addToast, showConfirmation, addActivityLog
}) => {
  const supabase = useSupabase();
  const [purchaseOrders, setPurchaseOrders] = useState<PurchaseOrder[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [products, setProducts] = useState<Product[]>([]);

  // Estados para o Modal
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentOrder, setCurrentOrder] = useState<Partial<PurchaseOrder> | null>(null);
  const [itemSearch, setItemSearch] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<SortConfig<PurchaseOrder> | null>(null);

  const fetchData = useCallback(async () => {
    const [po, s, p] = await Promise.all([
        supabase.from('purchase_orders').select('*'),
        supabase.from('suppliers').select('*').order('name'),
        supabase.from('products').select('*').order('name'),
    ]);
    if(po.data) setPurchaseOrders(po.data as unknown as PurchaseOrder[]);
    if(s.data) setSuppliers(s.data);
    if(p.data) setProducts(p.data);
  }, [supabase]);

  useEffect(() => {
    fetchData();
    const channel = supabase.channel('purchase-orders-db-changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'purchase_orders' }, () => fetchData())
      .subscribe();
    return () => { supabase.removeChannel(channel); }
  }, [supabase, fetchData]);

  const addStockMovement = useCallback(async (movement: Omit<StockMovement, 'id' | 'date' | 'user_id'>) => {
    await supabase.from('stock_movements').insert({ ...movement, date: new Date().toISOString() });
  }, [supabase]);

  const sortedOrders = useMemo(() => {
    let sortableItems = [...purchaseOrders].filter(o => o.supplier_name.toLowerCase().includes(searchTerm.toLowerCase()));
    if (sortConfig !== null) {
      sortableItems.sort((a, b) => {
        const key = sortConfig.key;
        if (key === 'created_at') {
            return new Date(a[key]).getTime() - new Date(b[key]).getTime() * (sortConfig.direction === 'ascending' ? 1 : -1);
        }
        const valA = String(a[key] || '');
        const valB = String(b[key] || '');
        return valA.localeCompare(valB) * (sortConfig.direction === 'ascending' ? 1 : -1);
      });
    } else {
        sortableItems.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
    }
    return sortableItems;
  }, [purchaseOrders, searchTerm, sortConfig]);

  // Filtro de produtos para a busca dentro do modal
  const filteredProductsSearch = useMemo(() => {
    if (!itemSearch.trim()) return [];
    return products.filter(p => 
        p.name.toLowerCase().includes(itemSearch.toLowerCase()) || 
        p.id.toLowerCase().includes(itemSearch.toLowerCase())
    ).slice(0, 5); // Limita a 5 resultados para não poluir
  }, [products, itemSearch]);

  const openModal = (order: PurchaseOrder | null = null) => {
    setCurrentOrder(order ? { ...order } : { supplier_id: suppliers[0]?.id || '', items: [], status: 'pending' });
    setItemSearch('');
    setIsModalOpen(true);
  };

  const addItemToOrder = (product: Product) => {
      if (!currentOrder) return;
      const items = [...(currentOrder.items || [])];
      if (items.some(i => i.product_id === product.id)) {
          addToast("Este item já foi adicionado.", "warning");
          return;
      }
      items.push({ product_id: product.id, product_name: product.name, quantity: 1 });
      setCurrentOrder({ ...currentOrder, items });
      setItemSearch('');
  };

  const removeItemFromOrder = (productId: string) => {
      if (!currentOrder) return;
      const items = (currentOrder.items || []).filter(i => i.product_id !== productId);
      setCurrentOrder({ ...currentOrder, items });
  };

  const handleQtyChange = (productId: string, qty: number) => {
      if (!currentOrder) return;
      const items = (currentOrder.items || []).map(i => 
          i.product_id === productId ? { ...i, quantity: qty } : i
      );
      setCurrentOrder({ ...currentOrder, items });
  };

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    if (!currentOrder || !currentOrder.supplier_id || !currentOrder.items || currentOrder.items.length === 0) {
        addToast("Fornecedor e pelo menos um item são obrigatórios.", 'error');
        return;
    }
    const supplier = suppliers.find(s => s.id === currentOrder.supplier_id);
    if (!supplier) return;

    const orderData = {
        supplier_id: supplier.id,
        supplier_name: supplier.name,
        status: currentOrder.status || 'pending',
        items: currentOrder.items as any,
        created_at: currentOrder.id ? currentOrder.created_at! : new Date().toISOString()
    };

    const { error } = currentOrder.id 
        ? await supabase.from('purchase_orders').update(orderData).eq('id', currentOrder.id)
        : await supabase.from('purchase_orders').insert(orderData);

    if (error) { 
        addToast(`Erro: ${error.message}`, 'error'); 
    } else {
        addToast(`Ordem de Compra ${currentOrder.id ? 'atualizada' : 'criada'}!`, 'success');
        addActivityLog(`${currentOrder.id ? 'atualizou' : 'criou'} OC para ${supplier.name}.`);
        setIsModalOpen(false);
        fetchData();
    }
  }

  const handleReceiveOrder = (order: PurchaseOrder) => {
    showConfirmation("Confirmar o recebimento desta ordem? Os itens serão adicionados ao saldo do estoque.", async () => {
        try {
            for (const item of order.items) {
                const product = products.find(p => p.id === item.product_id);
                if (product) {
                    await supabase.from('products').update({ quantity: product.quantity + item.quantity }).eq('id', item.product_id);
                    await addStockMovement({
                        product_id: item.product_id,
                        product_name: item.product_name,
                        type: 'in',
                        quantity: item.quantity,
                        reason: `Recebimento OC #${order.id.substring(0, 8)}`,
                    });
                }
            }
            await supabase.from('purchase_orders').update({ status: 'received' }).eq('id', order.id);
            addToast("Estoque atualizado com sucesso!", "success");
            fetchData();
        } catch (err) {
            addToast("Erro ao processar recebimento.", "error");
        }
    });
  }

  const columns = [
    { header: 'Fornecedor', accessor: 'supplier_name' as const, sortable: true },
    { header: 'Data', accessor: (item: PurchaseOrder) => new Date(item.created_at).toLocaleDateString('pt-BR'), sortable: true, sortKey: 'created_at' as const },
    { header: 'Itens', accessor: (item: PurchaseOrder) => `${item.items.length} tipo(s)` },
    { header: 'Status', accessor: (item: PurchaseOrder) => (
        <span className={`px-2 py-1 rounded-full text-xs font-bold ${item.status === 'received' ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'}`}>
            {item.status === 'received' ? 'RECEBIDO' : 'PENDENTE'}
        </span>
    ), sortable: true, sortKey: 'status' as const },
  ];

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-gray-800 dark:text-gray-200">Ordens de Compra</h2>
          <p className="text-gray-500 dark:text-gray-400">Gerencie seus pedidos e recebimentos.</p>
        </div>
        <button onClick={() => openModal()} className="bg-primary text-white px-4 py-2 rounded-lg shadow hover:bg-secondary transition">
          Nova Ordem
        </button>
      </div>

      <div className="relative">
          <input
              type="text"
              placeholder="Buscar por fornecedor..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 border rounded-lg dark:bg-gray-800 dark:border-gray-600 dark:text-gray-200"
          />
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
              <svg className="h-5 w-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
          </div>
      </div>

      <Table
          columns={columns}
          data={sortedOrders}
          sortConfig={sortConfig}
          requestSort={(key) => setSortConfig({ key, direction: sortConfig?.key === key && sortConfig.direction === 'ascending' ? 'descending' : 'ascending' })}
          actions={(order) => {
              const supplier = suppliers.find(s => s.id === order.supplier_id);
              const whatsappNumber = supplier?.whatsapp?.replace(/\D/g, '');
              const message = encodeURIComponent(`Olá, gostaria de confirmar o pedido:\nFornecedor: ${order.supplier_name}\n\nItens:\n${order.items.map(i => `- ${i.quantity}x ${i.product_name}`).join('\n')}`);

              return (
              <div className="flex space-x-2">
                  {order.status === 'pending' && (
                      <>
                        <button onClick={() => openModal(order)} title="Editar" className="text-indigo-600 hover:bg-indigo-100 p-1.5 rounded-md transition"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.5L16.732 3.732z" /></svg></button>
                        <button onClick={() => handleReceiveOrder(order)} title="Receber Pedido" className="text-green-600 hover:bg-green-100 p-1.5 rounded-md transition"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" /></svg></button>
                      </>
                  )}
                  {whatsappNumber && (
                      <a href={`https://wa.me/${whatsappNumber}?text=${message}`} target="_blank" rel="noopener noreferrer" className="text-green-500 hover:bg-green-50 p-1.5 rounded-md transition"><svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413Z"/></svg></a>
                  )}
              </div>
              );
          }}
      />

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={currentOrder?.id ? 'Editar Ordem' : 'Nova Ordem de Compra'}>
        <form onSubmit={handleSubmit} className="space-y-4">
            <div>
                <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Fornecedor Destino</label>
                <select 
                    value={currentOrder?.supplier_id} 
                    onChange={e => setCurrentOrder(prev => ({...prev, supplier_id: e.target.value}))} 
                    className="w-full p-3 border rounded-xl dark:bg-gray-800 dark:border-gray-700 dark:text-gray-200"
                    disabled={!!currentOrder?.id}
                >
                    <option value="">Selecione um fornecedor...</option>
                    {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
            </div>

            <div className="space-y-2">
                <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Adicionar Itens ao Pedido</label>
                <div className="relative">
                    <input 
                        type="text" 
                        placeholder="Pesquisar produto por nome ou código..."
                        value={itemSearch}
                        onChange={e => setItemSearch(e.target.value)}
                        className="w-full p-3 pl-10 border rounded-xl dark:bg-gray-800 dark:border-gray-700 dark:text-gray-200"
                    />
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <svg className="h-4 w-4 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
                    </div>

                    {/* Resultados da busca rápida */}
                    {filteredProductsSearch.length > 0 && (
                        <div className="absolute z-50 w-full mt-1 bg-white dark:bg-gray-800 border dark:border-gray-700 rounded-xl shadow-2xl overflow-hidden animate-fade-in">
                            {filteredProductsSearch.map(p => (
                                <button 
                                    key={p.id} 
                                    type="button"
                                    onClick={() => addItemToOrder(p)}
                                    className="w-full text-left p-3 hover:bg-gray-50 dark:hover:bg-gray-700 border-b last:border-0 dark:border-gray-700 flex justify-between items-center"
                                >
                                    <div>
                                        <p className="text-sm font-bold text-gray-800 dark:text-gray-100">{p.name}</p>
                                        <p className="text-[10px] text-gray-500 uppercase tracking-tighter">Cód: {p.id} | Saldo: {p.quantity}</p>
                                    </div>
                                    <svg className="w-5 h-5 text-primary" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6"></path></svg>
                                </button>
                            ))}
                        </div>
                    )}
                </div>
            </div>

            <div className="bg-gray-50 dark:bg-gray-900/50 p-4 rounded-2xl border dark:border-gray-800">
                <h4 className="text-sm font-bold mb-4 text-gray-700 dark:text-gray-300 flex items-center">
                    <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z"></path></svg>
                    Lista de Compra ({currentOrder?.items?.length || 0})
                </h4>
                <div className="max-h-64 overflow-y-auto space-y-3 pr-2">
                    {currentOrder?.items && currentOrder.items.length > 0 ? currentOrder.items.map(item => (
                        <div key={item.product_id} className="flex justify-between items-center p-3 bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 animate-fade-in">
                            <div className="flex-1">
                                <p className="text-xs font-bold text-gray-800 dark:text-gray-200 truncate pr-2 uppercase">{item.product_name}</p>
                                <p className="text-[10px] text-gray-500 font-mono">{item.product_id}</p>
                            </div>
                            <div className="flex items-center space-x-3">
                                <div className="flex flex-col items-center">
                                    <label className="text-[8px] font-bold text-gray-400 uppercase">Qtd</label>
                                    <input 
                                        type="number" 
                                        min="1" 
                                        value={item.quantity} 
                                        onChange={(e) => handleQtyChange(item.product_id, Number(e.target.value))}
                                        className="w-16 p-1 text-center font-bold border rounded-lg dark:bg-gray-700 dark:border-gray-600 dark:text-white"
                                    />
                                </div>
                                <button 
                                    type="button"
                                    onClick={() => removeItemFromOrder(item.product_id)}
                                    className="text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 p-2 rounded-lg transition"
                                >
                                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                                </button>
                            </div>
                        </div>
                    )) : (
                        <div className="text-center py-10">
                            <p className="text-sm text-gray-500 italic">Pesquise e selecione os itens acima para montar sua ordem.</p>
                        </div>
                    )}
                </div>
            </div>

            <div className="flex flex-col pt-4">
                <button type="submit" className="w-full py-4 bg-primary text-white font-bold rounded-xl shadow-lg hover:bg-secondary transition-all">
                    {currentOrder?.id ? 'Atualizar Ordem de Compra' : 'Confirmar e Gerar Ordem'}
                </button>
                <button type="button" onClick={() => setIsModalOpen(false)} className="mt-2 py-2 text-sm text-gray-500 hover:text-red-500 transition">Cancelar</button>
            </div>
        </form>
      </Modal>
    </div>
  );
};

import React, { useState, useMemo, FormEvent, useEffect, useCallback } from 'react';
import { Product, Employee, ToastMessage, User, WorkOrder, PriceHistory, ParsedNFe, NFeProduct } from '../types';
import { Table, SortConfig } from './shared/Table';
import { Modal } from './shared/Modal';
import { useSupabase } from '../contexts/SupabaseContext';
import { QRCodeModal } from './shared/QRCodeModal';
import { QRCodeScannerModal } from './shared/QRCodeScannerModal';
import { parseNFeXML, cleanName } from '../services/nfeParser';
import { parseFiscalDocument } from '../services/geminiService';

interface StockControlProps {
  addToast: (message: string, type: ToastMessage['type']) => void;
  showConfirmation: (message: string, onConfirm: () => void) => void;
  addActivityLog: (action: string) => void;
  currentUser: User;
}

export const StockControl: React.FC<StockControlProps> = ({ 
    addToast, showConfirmation, addActivityLog
}) => {
  const supabase = useSupabase();
  const [products, setProducts] = useState<Product[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [workOrders, setWorkOrders] = useState<WorkOrder[]>([]);
  const [priceHistory, setPriceHistory] = useState<PriceHistory[]>([]);
  const [isProcessingIA, setIsProcessingIA] = useState(false);

  // Estados para Seleção e Revisão
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [pendingImport, setPendingImport] = useState<ParsedNFe | null>(null);
  const [mappings, setMappings] = useState<Record<number, string | 'NEW'>>({});

  const fetchData = useCallback(async () => {
    const [p, e, wo] = await Promise.all([
      supabase.from('products').select('*').order('name'),
      supabase.from('employees').select('*'),
      supabase.from('work_orders').select('*'),
    ]);
    if (p.data) setProducts(p.data);
    if (e.data) setEmployees(e.data);
    if (wo.data) setWorkOrders(wo.data as unknown as WorkOrder[]);
  }, [supabase]);

  useEffect(() => {
    fetchData();
    const channel = supabase.channel('products-realtime')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'products' }, () => fetchData())
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [supabase, fetchData]);

  const [isProductModalOpen, setIsProductModalOpen] = useState(false);
  const [isStockModalOpen, setIsStockModalOpen] = useState(false);
  const [isScannerOpen, setIsScannerOpen] = useState(false);
  const [isQrModalOpen, setIsQrModalOpen] = useState(false);
  const [isPriceHistoryModalOpen, setIsPriceHistoryModalOpen] = useState(false);

  const [currentProduct, setCurrentProduct] = useState<Product | null>(null);
  const [stockAction, setStockAction] = useState<'in' | 'out'>('in');
  const [stockQuantity, setStockQuantity] = useState<number | string>(1);
  const [stockEmployeeId, setStockEmployeeId] = useState<string>('');
  const [stockWorkOrderId, setStockWorkOrderId] = useState<string>('');

  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<SortConfig<Product>>(null);

  const filteredProducts = useMemo(() => {
    return products.filter(p =>
      p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      p.id.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [products, searchTerm]);

  const requestSort = (key: keyof Product) => {
    let direction: 'ascending' | 'descending' = 'ascending';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'ascending') {
      direction = 'descending';
    }
    setSortConfig({ key, direction });
  };

  const sortedProducts = useMemo(() => {
    let sortableItems = [...filteredProducts];
    if (sortConfig !== null) {
      sortableItems.sort((a, b) => {
        const valA = a[sortConfig.key] || '';
        const valB = b[sortConfig.key] || '';
        if (valA < valB) return sortConfig.direction === 'ascending' ? -1 : 1;
        if (valA > valB) return sortConfig.direction === 'ascending' ? 1 : -1;
        return 0;
      });
    }
    return sortableItems;
  }, [filteredProducts, sortConfig]);

  const handleBulkDelete = () => {
    if (selectedIds.length === 0) return;

    showConfirmation(`Tem certeza que deseja excluir ${selectedIds.length} produtos selecionados? Esta ação não pode ser desfeita.`, async () => {
        const { error } = await supabase.from('products').delete().in('id', selectedIds);
        if (error) {
            addToast(`Erro ao excluir em massa: ${error.message}`, 'error');
        } else {
            addToast(`${selectedIds.length} produtos excluídos com sucesso!`, 'success');
            addActivityLog(`excluiu em massa ${selectedIds.length} produtos.`);
            setSelectedIds([]);
            await fetchData();
        }
    });
  };

  // Lógica de mapeamento inteligente na abertura do modal de revisão
  const openReviewModal = (parsed: ParsedNFe) => {
      const initialMappings: Record<number, string | 'NEW'> = {};

      parsed.products.forEach((p, index) => {
          const matchById = products.find(existing => existing.id === p.code);
          if (matchById) {
              initialMappings[index] = matchById.id;
              return;
          }
          const cleanNfeName = cleanName(p.name).toLowerCase();
          const matchByName = products.find(existing => cleanName(existing.name).toLowerCase() === cleanNfeName);
          if (matchByName) {
              initialMappings[index] = matchByName.id;
              return;
          }
          initialMappings[index] = 'NEW';
      });

      setMappings(initialMappings);
      setPendingImport(parsed);
  };

  const confirmFinalImport = async () => {
      if (!pendingImport) return;

      setIsProcessingIA(true);
      try {
          const { data: existingSupplier } = await supabase
              .from('suppliers')
              .select('id')
              .eq('cnpj', pendingImport.supplier.cnpj)
              .maybeSingle();

          if (!existingSupplier) {
              await supabase.from('suppliers').insert({
                  name: pendingImport.supplier.name,
                  cnpj: pendingImport.supplier.cnpj,
                  contact: 'Cadastrado via Importação'
              });
              addActivityLog(`cadastrou automaticamente o fornecedor ${pendingImport.supplier.name} via importação.`);
          }

          const { error: nfError } = await supabase.from('nfs').insert({
              supplier: { ...pendingImport.supplier, access_key: pendingImport.access_key || null } as any,
              products: pendingImport.products as any,
              total_value: pendingImport.total_value,
              import_date: new Date().toISOString()
          });

          if (nfError) throw new Error(`Erro ao salvar NF: ${nfError.message}`);

          for (let i = 0; i < pendingImport.products.length; i++) {
              const p = pendingImport.products[i];
              const mappingId = mappings[i];

              let targetId = p.code;
              if (mappingId && mappingId !== 'NEW') {
                  targetId = mappingId;
              }

              const { data: existing } = await supabase.from('products').select('*').eq('id', targetId).maybeSingle();

              if (!existing || existing.unit_price !== p.unit_price) {
                  await supabase.from('price_history').insert({
                      product_id: targetId,
                      price: p.unit_price,
                      date: new Date().toISOString(),
                      supplier_name: pendingImport.supplier.name
                  });
              }

              if (existing) {
                  await supabase.from('products').update({ 
                      quantity: existing.quantity + p.quantity,
                      unit_price: p.unit_price 
                  }).eq('id', targetId);
              } else {
                  await supabase.from('products').insert({
                      id: targetId,
                      name: p.name,
                      quantity: p.quantity,
                      unit_price: p.unit_price,
                      min_stock: 0
                  });
              }

              await supabase.from('stock_movements').insert({
                  product_id: targetId,
                  product_name: p.name,
                  type: 'in',
                  quantity: p.quantity,
                  date: new Date().toISOString(),
                  reason: `Importação: ${pendingImport.supplier.name}`
              });
          }

          addToast('Importação concluída com sucesso!', 'success');
          addActivityLog(`importou documento de ${pendingImport.supplier.name} com revisão.`);
          setPendingImport(null);
          await fetchData();
      } catch (err: any) {
          addToast(err.message, 'error');
      } finally {
          setIsProcessingIA(false);
      }
  };

  const handleImportXML = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (event) => {
      try {
        const xml = event.target?.result as string;
        const parsed = await parseNFeXML(xml);
        openReviewModal(parsed);
      } catch (err: any) {
        addToast(`Erro ao processar XML: ${err.message}`, 'error');
      }
    };
    reader.readAsText(file);
    e.target.value = ''; 
  };

  const handleImportCupom = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      setIsProcessingIA(true);
      addToast("Aguarde, a IA está analisando o cupom...", "info");
      const reader = new FileReader();
      reader.onload = async (event) => {
          try {
              const base64 = event.target?.result as string;
              const parsed = await parseFiscalDocument(base64, file.type);
              openReviewModal(parsed);
          } catch (err: any) {
              addToast(err.message || "Erro ao processar cupom com IA.", "error");
          } finally {
              setIsProcessingIA(false);
          }
      };
      reader.readAsDataURL(file);
      e.target.value = '';
  };

  const handleProductSubmit = async (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const name = formData.get('name') as string;
    const unit_price = parseFloat(formData.get('unitPrice') as string);
    const quantity = parseFloat(formData.get('quantity') as string);
    const min_stock = parseFloat(formData.get('minStock') as string);

    if (currentProduct?.id) {
      if (currentProduct.unit_price !== unit_price) {
          await supabase.from('price_history').insert({
              product_id: currentProduct.id,
              price: unit_price,
              date: new Date().toISOString(),
              supplier_name: 'Alteração Manual'
          });
      }
      const { error } = await supabase.from('products').update({ name, unit_price, quantity, min_stock }).eq('id', currentProduct.id);
      if (error) addToast(`Erro ao atualizar: ${error.message}`, 'error');
      else {
        addToast('Produto atualizado!', 'success');
        addActivityLog(`atualizou o produto ${name}`);
        await fetchData();
        setIsProductModalOpen(false);
      }
    } else {
      const id = formData.get('id') as string;
      const { error } = await supabase.from('products').insert({ id, name, unit_price, quantity, min_stock });
      if (error) addToast(`Erro ao cadastrar: ${error.message}`, 'error');
      else {
        await supabase.from('price_history').insert({ product_id: id, price: unit_price, date: new Date().toISOString(), supplier_name: 'Cadastro Inicial' });
        addToast('Produto cadastrado!', 'success');
        addActivityLog(`cadastrou o produto ${name}`);
        await fetchData();
        setIsProductModalOpen(false);
      }
    }
  };

  const handleStockAction = async () => {
    if (!currentProduct) return;
    const qty = parseFloat(stockQuantity as string);
    const newQty = stockAction === 'in' ? currentProduct.quantity + qty : currentProduct.quantity - qty;
    if (newQty < 0) { addToast('Erro: Estoque insuficiente.', 'error'); return; }
    const { error } = await supabase.from('products').update({ quantity: newQty }).eq('id', currentProduct.id);
    if (error) { addToast(`Erro ao movimentar: ${error.message}`, 'error'); return; }
    const employee = employees.find(e => e.id === stockEmployeeId);
    const movement = {
      product_id: currentProduct.id,
      product_name: currentProduct.name,
      type: stockAction,
      quantity: qty,
      date: new Date().toISOString(),
      employee_id: stockEmployeeId || null,
      employee_name: employee?.name || null,
      work_order_id: stockWorkOrderId || null,
      reason: stockAction === 'in' ? 'Entrada manual' : 'Saída manual',
    };
    await supabase.from('stock_movements').insert(movement);
    addToast('Estoque atualizado!', 'success');
    addActivityLog(`${stockAction === 'in' ? 'entrada' : 'saída'} de ${qty}x ${currentProduct.name}`);
    await fetchData();
    setIsStockModalOpen(false);
  };

  const handleDelete = (product: Product) => {
    showConfirmation(`Deseja excluir o produto ${product.name}?`, async () => {
      const { error } = await supabase.from('products').delete().eq('id', product.id);
      if (error) addToast(`Erro ao excluir: ${error.message}`, 'error');
      else {
        addToast('Produto excluído!', 'success');
        addActivityLog(`excluiu o produto ${product.name}`);
        await fetchData();
      }
    });
  };

  const viewPriceHistory = async (product: Product) => {
      setCurrentProduct(product);
      const { data } = await supabase.from('price_history').select('*').eq('product_id', product.id).order('date', { ascending: false });
      if (data) setPriceHistory(data as unknown as PriceHistory[]);
      setIsPriceHistoryModalOpen(true);
  };

  const columns = [
    { header: 'ID', accessor: 'id' as const, sortable: true },
    { header: 'Nome', accessor: 'name' as const, sortable: true },
    { header: 'Qtd', accessor: (item: Product) => item.quantity.toLocaleString('pt-BR', { minimumFractionDigits: 0, maximumFractionDigits: 3 }), sortable: true, sortKey: 'quantity' as const },
    { header: 'Preço', accessor: (item: Product) => item.unit_price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }), sortable: true, sortKey: 'unit_price' as const },
    { header: 'Mínimo', accessor: 'min_stock' as const, sortable: true },
  ];

  const formInputClass = "w-full p-3 border rounded-xl dark:bg-gray-800 dark:border-gray-700 dark:text-gray-200";

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-800 dark:text-gray-200">Controle de Estoque</h2>
          <p className="text-gray-500 dark:text-gray-400">Gerencie seus produtos de consumo e insumos.</p>
        </div>
        <div className="flex flex-wrap gap-2">
            {selectedIds.length > 0 && (
                <button 
                    onClick={handleBulkDelete}
                    className="bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700 transition flex items-center shadow-lg animate-pulse"
                >
                    <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                    Excluir ({selectedIds.length})
                </button>
            )}
            <label className={`bg-amber-600 text-white px-4 py-2 rounded-lg hover:bg-amber-700 transition flex items-center cursor-pointer shadow-lg ${isProcessingIA ? 'opacity-50 pointer-events-none' : ''}`}>
                {isProcessingIA ? (
                    <svg className="animate-spin h-5 w-5 mr-2" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                ) : (
                    <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"></path></svg>
                )}
                Importar Cupom (IA)
                <input type="file" accept="image/*,.pdf" className="hidden" onChange={handleImportCupom} disabled={isProcessingIA} />
            </label>
            <label className="bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition flex items-center cursor-pointer shadow-lg">
                <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
                XML NFe
                <input type="file" accept=".xml" className="hidden" onChange={handleImportXML} />
            </label>
            <button onClick={() => setIsScannerOpen(true)} className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition flex items-center shadow-lg">
                <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg>
                Escanear
            </button>
            <button onClick={() => { setCurrentProduct(null); setIsProductModalOpen(true); }} className="bg-primary text-white px-4 py-2 rounded-lg hover:bg-secondary transition shadow-lg">
                Novo Produto
            </button>
        </div>
      </div>

      <div className="relative">
        <input
          type="text"
          placeholder="Buscar por nome ou ID..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="w-full pl-10 pr-4 py-2 border rounded-lg dark:bg-gray-800 dark:border-gray-600 dark:text-gray-200"
        />
        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
          <svg className="h-5 w-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
        </div>
      </div>

      <Table<Product>
        columns={columns}
        data={sortedProducts}
        sortConfig={sortConfig}
        requestSort={requestSort}
        selectedItems={selectedIds}
        setSelectedItems={setSelectedIds}
        actions={(product) => (
          <div className="flex space-x-2">
            <button onClick={() => { setCurrentProduct(product); setStockAction('in'); setStockQuantity(1); setIsStockModalOpen(true); }} title="Entrada" className="text-green-600 hover:bg-green-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"></path></svg></button>
            <button onClick={() => { setCurrentProduct(product); setStockAction('out'); setStockQuantity(1); setIsStockModalOpen(true); }} title="Saída" className="text-amber-600 hover:bg-amber-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 12H4"></path></svg></button>
            <button onClick={() => viewPriceHistory(product)} title="Histórico de Preço" className="text-purple-600 hover:bg-purple-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6"></path></svg></button>
            <button onClick={() => { setCurrentProduct(product); setIsQrModalOpen(true); }} title="QR Code" className="text-gray-600 hover:bg-gray-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg></button>
            <button onClick={() => { setCurrentProduct(product); setIsProductModalOpen(true); }} title="Editar" className="text-indigo-600 hover:text-indigo-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg></button>
            <button onClick={() => handleDelete(product)} title="Excluir" className="text-red-600 hover:bg-red-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg></button>
          </div>
        )}
      />

      {/* MODAL DE REVISÃO DE IMPORTAÇÃO */}
      <Modal isOpen={!!pendingImport} onClose={() => setPendingImport(null)} title={`Revisão de Importação: ${pendingImport?.supplier.name}`}>
          <div className="space-y-6">
              <p className="text-sm text-gray-500">Verifique os itens abaixo e vincule-os corretamente.</p>
              <div className="max-h-[500px] overflow-y-auto space-y-4 pr-2">
                  {pendingImport?.products.map((item, idx) => (
                      <div key={idx} className="p-4 border dark:border-gray-700 rounded-xl bg-gray-50 dark:bg-gray-800/50 space-y-3">
                          <div className="flex justify-between items-start">
                              <div className="flex-1">
                                  <h4 className="text-sm font-bold text-gray-800 dark:text-gray-100 uppercase">{item.name}</h4>
                                  <p className="text-[10px] text-gray-500 font-mono">Cód. Nota: {item.code} | Vlr: {item.unit_price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</p>
                              </div>
                              <div className="text-right ml-4"><span className="text-sm font-bold text-primary">+{item.quantity} un</span></div>
                          </div>
                          <div>
                              <label className="text-[10px] font-bold uppercase text-gray-400 mb-1 block">Vincular ao Produto:</label>
                              <select value={mappings[idx]} onChange={e => setMappings(prev => ({...prev, [idx]: e.target.value}))} className="w-full p-2 text-xs border rounded-lg dark:bg-gray-700 dark:border-gray-600">
                                  <option value="NEW">✨ CADASTRAR COMO NOVO ITEM</option>
                                  <optgroup label="PRODUTOS EM ESTOQUE">
                                      {products.map(p => (<option key={p.id} value={p.id}>{p.name} (Saldo: {p.quantity})</option>))}
                                  </optgroup>
                              </select>
                          </div>
                      </div>
                  ))}
              </div>
              <div className="flex flex-col space-y-2">
                  <button onClick={confirmFinalImport} disabled={isProcessingIA} className="w-full py-4 bg-primary text-white font-bold rounded-xl shadow-lg hover:bg-secondary transition disabled:opacity-50">{isProcessingIA ? 'Processando...' : 'Confirmar e Alimentar Estoque'}</button>
                  <button onClick={() => setPendingImport(null)} className="w-full py-2 text-sm text-gray-500 hover:text-red-500 transition">Cancelar Importação</button>
              </div>
          </div>
      </Modal>

      {/* Histórico de Preços */}
      <Modal isOpen={isPriceHistoryModalOpen} onClose={() => setIsPriceHistoryModalOpen(false)} title={`Histórico de Preços: ${currentProduct?.name}`}>
          <div className="space-y-4">
              <div className="max-h-[400px] overflow-y-auto">
                  <table className="w-full text-left">
                      <thead className="bg-gray-50 dark:bg-gray-700 sticky top-0">
                          <tr>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500">Data</th>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500">Fornecedor/Origem</th>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500 text-right">Preço</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y dark:divide-gray-700">
                          {priceHistory.map((h, idx) => (
                              <tr key={idx} className="hover:bg-gray-50 dark:hover:bg-gray-800">
                                  <td className="p-3 text-sm">{new Date(h.date).toLocaleDateString('pt-BR')}</td>
                                  <td className="p-3 text-sm font-medium">{h.supplier_name || 'N/A'}</td>
                                  <td className="p-3 text-sm font-bold text-right text-primary">{h.price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</td>
                              </tr>
                          ))}
                      </tbody>
                  </table>
              </div>
          </div>
      </Modal>

      <Modal isOpen={isProductModalOpen} onClose={() => setIsProductModalOpen(false)} title={currentProduct?.id ? 'Ficha do Produto' : 'Novo Produto'}>
        <form onSubmit={handleProductSubmit} className="space-y-4">
            <div>
                <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Nome Interno</label>
                <input type="text" name="name" defaultValue={currentProduct?.name || ''} required className={formInputClass} />
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">ID Interno</label>
                    <input type="text" name="id" defaultValue={currentProduct?.id || ''} required disabled={!!currentProduct?.id} className={`${formInputClass} bg-gray-50 dark:bg-gray-900 disabled:text-gray-400`} />
                </div>
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Preço Custo (R$)</label>
                    <input type="number" step="0.01" name="unitPrice" defaultValue={currentProduct?.unit_price ?? ''} required className={`${formInputClass} font-bold text-primary`} />
                </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Qtd Atual</label>
                    <input type="number" step="0.001" name="quantity" defaultValue={currentProduct?.quantity ?? ''} required className={formInputClass} />
                </div>
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Mínimo</label>
                    <input type="number" step="1" name="minStock" defaultValue={currentProduct?.min_stock ?? ''} required className={formInputClass} />
                </div>
            </div>
            <button type="submit" className="w-full py-4 bg-primary text-white font-bold rounded-xl shadow-lg mt-4 transition hover:bg-secondary">Gravar Alterações</button>
        </form>
      </Modal>

      {/* MODAL DE MOVIMENTAÇÃO MELHORADO */}
      <Modal isOpen={isStockModalOpen} onClose={() => setIsStockModalOpen(false)} title={`Movimentação: ${currentProduct?.name}`}>
          <div className="space-y-6">
              {/* Card de Saldo Atual */}
              <div className="bg-gray-50 dark:bg-gray-800 p-4 rounded-2xl border dark:border-gray-700 flex justify-between items-center">
                  <div>
                      <p className="text-[10px] font-bold uppercase text-gray-400 tracking-wider">Estoque em Mãos</p>
                      <p className="text-2xl font-black text-gray-800 dark:text-white">
                          {currentProduct?.quantity.toLocaleString('pt-BR', { minimumFractionDigits: 0, maximumFractionDigits: 3 })}
                      </p>
                  </div>
                  <div className={`p-3 rounded-xl ${stockAction === 'in' ? 'bg-green-100 dark:bg-green-900/30 text-green-600' : 'bg-amber-100 dark:bg-amber-900/30 text-amber-600'}`}>
                      {stockAction === 'in' ? (
                          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 11l5-5m0 0l5 5m-5-5v12"></path></svg>
                      ) : (
                          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 13l-5 5m0 0l-5-5m5 5V6"></path></svg>
                      )}
                  </div>
              </div>

              <div>
                  <label className="block text-xs font-bold uppercase text-gray-500 mb-2">Quantidade para {stockAction === 'in' ? 'Entrada' : 'Saída'}</label>
                  <input 
                      type="number" 
                      value={stockQuantity} 
                      onChange={e => setStockQuantity(e.target.value)} 
                      min="0.001" 
                      step="0.001" 
                      placeholder="Ex: 0,68"
                      className="w-full p-4 text-xl font-bold border-2 rounded-2xl focus:ring-4 focus:ring-primary/10 transition-all dark:bg-gray-800 dark:border-gray-700 dark:text-gray-100" 
                  />
                  <p className="text-[10px] text-gray-400 mt-2 italic">Dica: Use vírgula ou ponto para quantidades fracionadas.</p>
              </div>

              {stockAction === 'out' && (
                  <div className="space-y-4 animate-fade-in">
                    <div>
                        <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Funcionário Responsável</label>
                        <select value={stockEmployeeId} onChange={e => setStockEmployeeId(e.target.value)} className={formInputClass}>
                            <option value="">Selecione quem está retirando...</option>
                            {employees.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
                        </select>
                    </div>
                    <div>
                        <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Vincular à Ordem de Serviço (Opcional)</label>
                        <select value={stockWorkOrderId} onChange={e => setStockWorkOrderId(e.target.value)} className={formInputClass}>
                            <option value="">Nenhuma / Uso Geral na Oficina</option>
                            {workOrders.map(wo => <option key={wo.id} value={wo.id}>{wo.title}</option>)}
                        </select>
                    </div>
                  </div>
              )}

              <div className="pt-2">
                  <button 
                      onClick={handleStockAction} 
                      className={`w-full py-4 rounded-2xl font-bold text-white shadow-xl transition-all active:scale-95 flex items-center justify-center space-x-2 ${stockAction === 'in' ? 'bg-green-600 hover:bg-green-700 shadow-green-500/20' : 'bg-amber-600 hover:bg-amber-700 shadow-amber-500/20'}`}
                  >
                      <span>Confirmar {stockAction === 'in' ? 'Entrada no Estoque' : 'Saída do Material'}</span>
                  </button>
                  <button onClick={() => setIsStockModalOpen(false)} className="w-full mt-2 py-2 text-sm text-gray-500 hover:text-red-500 transition">Cancelar Operação</button>
              </div>
          </div>
      </Modal>

      {currentProduct && (
        <QRCodeModal isOpen={isQrModalOpen} onClose={() => setIsQrModalOpen(false)} title={`QR Code: ${currentProduct.name}`} data={currentProduct.id} />
      )}
      <QRCodeScannerModal isOpen={isScannerOpen} onClose={() => setIsScannerOpen(false)} onScan={(data) => { setSearchTerm(data); addToast(`Produto ${data} localizado`, 'success'); }} addToast={addToast} />
    </div>
  );
};

import React, { useState, useMemo, FormEvent, useEffect, useCallback } from 'react';
import { Product, Employee, ToastMessage, User, WorkOrder, PriceHistory, ParsedNFe, NFeProduct } from '../types';
import { Table, SortConfig } from './shared/Table';
import { Modal } from './shared/Modal';
import { useSupabase } from '../contexts/SupabaseContext';
import { QRCodeModal } from './shared/QRCodeModal';
import { QRCodeScannerModal } from './shared/QRCodeScannerModal';
import { parseNFeXML, cleanName } from '../services/nfeParser';
import { parseFiscalDocument } from '../services/geminiService';

interface StockControlProps {
  addToast: (message: string, type: ToastMessage['type']) => void;
  showConfirmation: (message: string, onConfirm: () => void) => void;
  addActivityLog: (action: string) => void;
  currentUser: User;
}

export const StockControl: React.FC<StockControlProps> = ({ 
    addToast, showConfirmation, addActivityLog
}) => {
  const supabase = useSupabase();
  const [products, setProducts] = useState<Product[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [workOrders, setWorkOrders] = useState<WorkOrder[]>([]);
  const [priceHistory, setPriceHistory] = useState<PriceHistory[]>([]);
  const [isProcessingIA, setIsProcessingIA] = useState(false);

  // Estados para Seleção e Revisão
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [pendingImport, setPendingImport] = useState<ParsedNFe | null>(null);
  const [mappings, setMappings] = useState<Record<number, string | 'NEW'>>({});

  const fetchData = useCallback(async () => {
    const [p, e, wo] = await Promise.all([
      supabase.from('products').select('*').order('name'),
      supabase.from('employees').select('*'),
      supabase.from('work_orders').select('*'),
    ]);
    if (p.data) setProducts(p.data);
    if (e.data) setEmployees(e.data);
    if (wo.data) setWorkOrders(wo.data as unknown as WorkOrder[]);
  }, [supabase]);

  useEffect(() => {
    fetchData();
    const channel = supabase.channel('products-realtime')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'products' }, () => fetchData())
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [supabase, fetchData]);

  const [isProductModalOpen, setIsProductModalOpen] = useState(false);
  const [isStockModalOpen, setIsStockModalOpen] = useState(false);
  const [isScannerOpen, setIsScannerOpen] = useState(false);
  const [isQrModalOpen, setIsQrModalOpen] = useState(false);
  const [isPriceHistoryModalOpen, setIsPriceHistoryModalOpen] = useState(false);

  const [currentProduct, setCurrentProduct] = useState<Product | null>(null);
  const [stockAction, setStockAction] = useState<'in' | 'out'>('in');
  const [stockQuantity, setStockQuantity] = useState<number | string>(1);
  const [stockEmployeeId, setStockEmployeeId] = useState<string>('');
  const [stockWorkOrderId, setStockWorkOrderId] = useState<string>('');

  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<SortConfig<Product>>(null);

  const filteredProducts = useMemo(() => {
    return products.filter(p =>
      p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      p.id.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [products, searchTerm]);

  const requestSort = (key: keyof Product) => {
    let direction: 'ascending' | 'descending' = 'ascending';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'ascending') {
      direction = 'descending';
    }
    setSortConfig({ key, direction });
  };

  const sortedProducts = useMemo(() => {
    let sortableItems = [...filteredProducts];
    if (sortConfig !== null) {
      sortableItems.sort((a, b) => {
        const valA = a[sortConfig.key] || '';
        const valB = b[sortConfig.key] || '';
        if (valA < valB) return sortConfig.direction === 'ascending' ? -1 : 1;
        if (valA > valB) return sortConfig.direction === 'ascending' ? 1 : -1;
        return 0;
      });
    }
    return sortableItems;
  }, [filteredProducts, sortConfig]);

  const handleBulkDelete = () => {
    if (selectedIds.length === 0) return;

    showConfirmation(`Tem certeza que deseja excluir ${selectedIds.length} produtos selecionados? Esta ação não pode ser desfeita.`, async () => {
        const { error } = await supabase.from('products').delete().in('id', selectedIds);
        if (error) {
            addToast(`Erro ao excluir em massa: ${error.message}`, 'error');
        } else {
            addToast(`${selectedIds.length} produtos excluídos com sucesso!`, 'success');
            addActivityLog(`excluiu em massa ${selectedIds.length} produtos.`);
            setSelectedIds([]);
            await fetchData();
        }
    });
  };

  // Lógica de mapeamento inteligente na abertura do modal de revisão
  const openReviewModal = (parsed: ParsedNFe) => {
      const initialMappings: Record<number, string | 'NEW'> = {};

      parsed.products.forEach((p, index) => {
          const matchById = products.find(existing => existing.id === p.code);
          if (matchById) {
              initialMappings[index] = matchById.id;
              return;
          }
          const cleanNfeName = cleanName(p.name).toLowerCase();
          const matchByName = products.find(existing => cleanName(existing.name).toLowerCase() === cleanNfeName);
          if (matchByName) {
              initialMappings[index] = matchByName.id;
              return;
          }
          initialMappings[index] = 'NEW';
      });

      setMappings(initialMappings);
      setPendingImport(parsed);
  };

  const confirmFinalImport = async () => {
      if (!pendingImport) return;

      setIsProcessingIA(true);
      try {
          const { data: existingSupplier } = await supabase
              .from('suppliers')
              .select('id')
              .eq('cnpj', pendingImport.supplier.cnpj)
              .maybeSingle();

          if (!existingSupplier) {
              await supabase.from('suppliers').insert({
                  name: pendingImport.supplier.name,
                  cnpj: pendingImport.supplier.cnpj,
                  contact: 'Cadastrado via Importação'
              });
              addActivityLog(`cadastrou automaticamente o fornecedor ${pendingImport.supplier.name} via importação.`);
          }

          const { error: nfError } = await supabase.from('nfs').insert({
              supplier: { ...pendingImport.supplier, access_key: pendingImport.access_key || null } as any,
              products: pendingImport.products as any,
              total_value: pendingImport.total_value,
              import_date: new Date().toISOString()
          });

          if (nfError) throw new Error(`Erro ao salvar NF: ${nfError.message}`);

          for (let i = 0; i < pendingImport.products.length; i++) {
              const p = pendingImport.products[i];
              const mappingId = mappings[i];

              let targetId = p.code;
              if (mappingId && mappingId !== 'NEW') {
                  targetId = mappingId;
              }

              const { data: existing } = await supabase.from('products').select('*').eq('id', targetId).maybeSingle();

              if (!existing || existing.unit_price !== p.unit_price) {
                  await supabase.from('price_history').insert({
                      product_id: targetId,
                      price: p.unit_price,
                      date: new Date().toISOString(),
                      supplier_name: pendingImport.supplier.name
                  });
              }

              if (existing) {
                  await supabase.from('products').update({ 
                      quantity: existing.quantity + p.quantity,
                      unit_price: p.unit_price 
                  }).eq('id', targetId);
              } else {
                  await supabase.from('products').insert({
                      id: targetId,
                      name: p.name,
                      quantity: p.quantity,
                      unit_price: p.unit_price,
                      min_stock: 0
                  });
              }

              await supabase.from('stock_movements').insert({
                  product_id: targetId,
                  product_name: p.name,
                  type: 'in',
                  quantity: p.quantity,
                  date: new Date().toISOString(),
                  reason: `Importação: ${pendingImport.supplier.name}`
              });
          }

          addToast('Importação concluída com sucesso!', 'success');
          addActivityLog(`importou documento de ${pendingImport.supplier.name} com revisão.`);
          setPendingImport(null);
          await fetchData();
      } catch (err: any) {
          addToast(err.message, 'error');
      } finally {
          setIsProcessingIA(false);
      }
  };

  const handleImportXML = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (event) => {
      try {
        const xml = event.target?.result as string;
        const parsed = await parseNFeXML(xml);
        openReviewModal(parsed);
      } catch (err: any) {
        addToast(`Erro ao processar XML: ${err.message}`, 'error');
      }
    };
    reader.readAsText(file);
    e.target.value = ''; 
  };

  const handleImportCupom = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      setIsProcessingIA(true);
      addToast("Aguarde, a IA está analisando o cupom...", "info");
      const reader = new FileReader();
      reader.onload = async (event) => {
          try {
              const base64 = event.target?.result as string;
              const parsed = await parseFiscalDocument(base64, file.type);
              openReviewModal(parsed);
          } catch (err: any) {
              addToast(err.message || "Erro ao processar cupom com IA.", "error");
          } finally {
              setIsProcessingIA(false);
          }
      };
      reader.readAsDataURL(file);
      e.target.value = '';
  };

  const handleProductSubmit = async (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const name = formData.get('name') as string;
    const unit_price = parseFloat(formData.get('unitPrice') as string);
    const quantity = parseFloat(formData.get('quantity') as string);
    const min_stock = parseFloat(formData.get('minStock') as string);

    if (currentProduct?.id) {
      if (currentProduct.unit_price !== unit_price) {
          await supabase.from('price_history').insert({
              product_id: currentProduct.id,
              price: unit_price,
              date: new Date().toISOString(),
              supplier_name: 'Alteração Manual'
          });
      }
      const { error } = await supabase.from('products').update({ name, unit_price, quantity, min_stock }).eq('id', currentProduct.id);
      if (error) addToast(`Erro ao atualizar: ${error.message}`, 'error');
      else {
        addToast('Produto atualizado!', 'success');
        addActivityLog(`atualizou o produto ${name}`);
        await fetchData();
        setIsProductModalOpen(false);
      }
    } else {
      const id = formData.get('id') as string;
      const { error } = await supabase.from('products').insert({ id, name, unit_price, quantity, min_stock });
      if (error) addToast(`Erro ao cadastrar: ${error.message}`, 'error');
      else {
        await supabase.from('price_history').insert({ product_id: id, price: unit_price, date: new Date().toISOString(), supplier_name: 'Cadastro Inicial' });
        addToast('Produto cadastrado!', 'success');
        addActivityLog(`cadastrou o produto ${name}`);
        await fetchData();
        setIsProductModalOpen(false);
      }
    }
  };

  const handleStockAction = async () => {
    if (!currentProduct) return;
    const qty = parseFloat(stockQuantity as string);
    const newQty = stockAction === 'in' ? currentProduct.quantity + qty : currentProduct.quantity - qty;
    if (newQty < 0) { addToast('Erro: Estoque insuficiente.', 'error'); return; }
    const { error } = await supabase.from('products').update({ quantity: newQty }).eq('id', currentProduct.id);
    if (error) { addToast(`Erro ao movimentar: ${error.message}`, 'error'); return; }
    const employee = employees.find(e => e.id === stockEmployeeId);
    const movement = {
      product_id: currentProduct.id,
      product_name: currentProduct.name,
      type: stockAction,
      quantity: qty,
      date: new Date().toISOString(),
      employee_id: stockEmployeeId || null,
      employee_name: employee?.name || null,
      work_order_id: stockWorkOrderId || null,
      reason: stockAction === 'in' ? 'Entrada manual' : 'Saída manual',
    };
    await supabase.from('stock_movements').insert(movement);
    addToast('Estoque atualizado!', 'success');
    addActivityLog(`${stockAction === 'in' ? 'entrada' : 'saída'} de ${qty}x ${currentProduct.name}`);
    await fetchData();
    setIsStockModalOpen(false);
  };

  const handleDelete = (product: Product) => {
    showConfirmation(`Deseja excluir o produto ${product.name}?`, async () => {
      const { error } = await supabase.from('products').delete().eq('id', product.id);
      if (error) addToast(`Erro ao excluir: ${error.message}`, 'error');
      else {
        addToast('Produto excluído!', 'success');
        addActivityLog(`excluiu o produto ${product.name}`);
        await fetchData();
      }
    });
  };

  const viewPriceHistory = async (product: Product) => {
      setCurrentProduct(product);
      const { data } = await supabase.from('price_history').select('*').eq('product_id', product.id).order('date', { ascending: false });
      if (data) setPriceHistory(data as unknown as PriceHistory[]);
      setIsPriceHistoryModalOpen(true);
  };

  const columns = [
    { header: 'ID', accessor: 'id' as const, sortable: true },
    { header: 'Nome', accessor: 'name' as const, sortable: true },
    { header: 'Qtd', accessor: (item: Product) => item.quantity.toLocaleString('pt-BR', { minimumFractionDigits: 0, maximumFractionDigits: 3 }), sortable: true, sortKey: 'quantity' as const },
    { header: 'Preço', accessor: (item: Product) => item.unit_price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }), sortable: true, sortKey: 'unit_price' as const },
    { header: 'Mínimo', accessor: 'min_stock' as const, sortable: true },
  ];

  const formInputClass = "w-full p-3 border rounded-xl dark:bg-gray-800 dark:border-gray-700 dark:text-gray-200";

  const FractionButton = ({ label, value }: { label: string, value: number }) => (
    <button 
        type="button"
        onClick={() => setStockQuantity(value)}
        className="flex-1 py-2 px-3 bg-gray-100 dark:bg-gray-700 hover:bg-primary hover:text-white dark:hover:bg-primary transition-all rounded-lg text-sm font-bold text-gray-600 dark:text-gray-300"
    >
        {label}
    </button>
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-800 dark:text-gray-200">Controle de Estoque</h2>
          <p className="text-gray-500 dark:text-gray-400">Gerencie seus produtos de consumo e insumos.</p>
        </div>
        <div className="flex flex-wrap gap-2">
            {selectedIds.length > 0 && (
                <button 
                    onClick={handleBulkDelete}
                    className="bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700 transition flex items-center shadow-lg animate-pulse"
                >
                    <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                    Excluir ({selectedIds.length})
                </button>
            )}
            <label className={`bg-amber-600 text-white px-4 py-2 rounded-lg hover:bg-amber-700 transition flex items-center cursor-pointer shadow-lg ${isProcessingIA ? 'opacity-50 pointer-events-none' : ''}`}>
                {isProcessingIA ? (
                    <svg className="animate-spin h-5 w-5 mr-2" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                ) : (
                    <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"></path></svg>
                )}
                Importar Cupom (IA)
                <input type="file" accept="image/*,.pdf" className="hidden" onChange={handleImportCupom} disabled={isProcessingIA} />
            </label>
            <label className="bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition flex items-center cursor-pointer shadow-lg">
                <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
                XML NFe
                <input type="file" accept=".xml" className="hidden" onChange={handleImportXML} />
            </label>
            <button onClick={() => setIsScannerOpen(true)} className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition flex items-center shadow-lg">
                <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg>
                Escanear
            </button>
            <button onClick={() => { setCurrentProduct(null); setIsProductModalOpen(true); }} className="bg-primary text-white px-4 py-2 rounded-lg hover:bg-secondary transition shadow-lg">
                Novo Produto
            </button>
        </div>
      </div>

      <div className="relative">
        <input
          type="text"
          placeholder="Buscar por nome ou ID..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="w-full pl-10 pr-4 py-2 border rounded-lg dark:bg-gray-800 dark:border-gray-600 dark:text-gray-200"
        />
        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
          <svg className="h-5 w-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
        </div>
      </div>

      <Table<Product>
        columns={columns}
        data={sortedProducts}
        sortConfig={sortConfig}
        requestSort={requestSort}
        selectedItems={selectedIds}
        setSelectedItems={setSelectedIds}
        actions={(product) => (
          <div className="flex space-x-2">
            <button onClick={() => { setCurrentProduct(product); setStockAction('in'); setStockQuantity(1); setIsStockModalOpen(true); }} title="Entrada" className="text-green-600 hover:bg-green-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"></path></svg></button>
            <button onClick={() => { setCurrentProduct(product); setStockAction('out'); setStockQuantity(1); setIsStockModalOpen(true); }} title="Saída" className="text-amber-600 hover:bg-amber-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 12H4"></path></svg></button>
            <button onClick={() => viewPriceHistory(product)} title="Histórico de Preço" className="text-purple-600 hover:bg-purple-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6"></path></svg></button>
            <button onClick={() => { setCurrentProduct(product); setIsQrModalOpen(true); }} title="QR Code" className="text-gray-600 hover:bg-gray-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg></button>
            <button onClick={() => { setCurrentProduct(product); setIsProductModalOpen(true); }} title="Editar" className="text-indigo-600 hover:text-indigo-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg></button>
            <button onClick={() => handleDelete(product)} title="Excluir" className="text-red-600 hover:bg-red-100 p-1.5 rounded-full transition"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg></button>
          </div>
        )}
      />

      {/* MODAL DE REVISÃO DE IMPORTAÇÃO */}
      <Modal isOpen={!!pendingImport} onClose={() => setPendingImport(null)} title={`Revisão de Importação: ${pendingImport?.supplier.name}`}>
          <div className="space-y-6">
              <p className="text-sm text-gray-500">Verifique os itens abaixo e vincule-os corretamente.</p>
              <div className="max-h-[500px] overflow-y-auto space-y-4 pr-2">
                  {pendingImport?.products.map((item, idx) => (
                      <div key={idx} className="p-4 border dark:border-gray-700 rounded-xl bg-gray-50 dark:bg-gray-800/50 space-y-3">
                          <div className="flex justify-between items-start">
                              <div className="flex-1">
                                  <h4 className="text-sm font-bold text-gray-800 dark:text-gray-100 uppercase">{item.name}</h4>
                                  <p className="text-[10px] text-gray-500 font-mono">Cód. Nota: {item.code} | Vlr: {item.unit_price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</p>
                              </div>
                              <div className="text-right ml-4"><span className="text-sm font-bold text-primary">+{item.quantity} un</span></div>
                          </div>
                          <div>
                              <label className="text-[10px] font-bold uppercase text-gray-400 mb-1 block">Vincular ao Produto:</label>
                              <select value={mappings[idx]} onChange={e => setMappings(prev => ({...prev, [idx]: e.target.value}))} className="w-full p-2 text-xs border rounded-lg dark:bg-gray-700 dark:border-gray-600">
                                  <option value="NEW">✨ CADASTRAR COMO NOVO ITEM</option>
                                  <optgroup label="PRODUTOS EM ESTOQUE">
                                      {products.map(p => (<option key={p.id} value={p.id}>{p.name} (Saldo: {p.quantity})</option>))}
                                  </optgroup>
                              </select>
                          </div>
                      </div>
                  ))}
              </div>
              <div className="flex flex-col space-y-2">
                  <button onClick={confirmFinalImport} disabled={isProcessingIA} className="w-full py-4 bg-primary text-white font-bold rounded-xl shadow-lg hover:bg-secondary transition disabled:opacity-50">{isProcessingIA ? 'Processando...' : 'Confirmar e Alimentar Estoque'}</button>
                  <button onClick={() => setPendingImport(null)} className="w-full py-2 text-sm text-gray-500 hover:text-red-500 transition">Cancelar Importação</button>
              </div>
          </div>
      </Modal>

      {/* Histórico de Preços */}
      <Modal isOpen={isPriceHistoryModalOpen} onClose={() => setIsPriceHistoryModalOpen(false)} title={`Histórico de Preços: ${currentProduct?.name}`}>
          <div className="space-y-4">
              <div className="max-h-[400px] overflow-y-auto">
                  <table className="w-full text-left">
                      <thead className="bg-gray-50 dark:bg-gray-700 sticky top-0">
                          <tr>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500">Data</th>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500">Fornecedor/Origem</th>
                              <th className="p-3 text-xs font-bold uppercase text-gray-500 text-right">Preço</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y dark:divide-gray-700">
                          {priceHistory.map((h, idx) => (
                              <tr key={idx} className="hover:bg-gray-50 dark:hover:bg-gray-800">
                                  <td className="p-3 text-sm">{new Date(h.date).toLocaleDateString('pt-BR')}</td>
                                  <td className="p-3 text-sm font-medium">{h.supplier_name || 'N/A'}</td>
                                  <td className="p-3 text-sm font-bold text-right text-primary">{h.price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</td>
                              </tr>
                          ))}
                      </tbody>
                  </table>
              </div>
          </div>
      </Modal>

      <Modal isOpen={isProductModalOpen} onClose={() => setIsProductModalOpen(false)} title={currentProduct?.id ? 'Ficha do Produto' : 'Novo Produto'}>
        <form onSubmit={handleProductSubmit} className="space-y-4">
            <div>
                <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Nome Interno</label>
                <input type="text" name="name" defaultValue={currentProduct?.name || ''} required className={formInputClass} />
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">ID Interno</label>
                    <input type="text" name="id" defaultValue={currentProduct?.id || ''} required disabled={!!currentProduct?.id} className={`${formInputClass} bg-gray-50 dark:bg-gray-900 disabled:text-gray-400`} />
                </div>
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Preço Custo (R$)</label>
                    <input type="number" step="0.01" name="unitPrice" defaultValue={currentProduct?.unit_price ?? ''} required className={`${formInputClass} font-bold text-primary`} />
                </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Qtd Atual</label>
                    <input type="number" step="0.001" name="quantity" defaultValue={currentProduct?.quantity ?? ''} required className={formInputClass} />
                </div>
                <div>
                    <label className="text-[11px] font-bold uppercase text-gray-500 mb-1 block">Mínimo</label>
                    <input type="number" step="1" name="minStock" defaultValue={currentProduct?.min_stock ?? ''} required className={formInputClass} />
                </div>
            </div>
            <button type="submit" className="w-full py-4 bg-primary text-white font-bold rounded-xl shadow-lg mt-4 transition hover:bg-secondary">Gravar Alterações</button>
        </form>
      </Modal>

      {/* MODAL DE MOVIMENTAÇÃO MELHORADO COM ATALHOS DE FRAÇÃO */}
      <Modal isOpen={isStockModalOpen} onClose={() => setIsStockModalOpen(false)} title={`Movimentação: ${currentProduct?.name}`}>
          <div className="space-y-6">
              {/* Card de Saldo Atual */}
              <div className="bg-gray-50 dark:bg-gray-800 p-4 rounded-2xl border dark:border-gray-700 flex justify-between items-center">
                  <div>
                      <p className="text-[10px] font-bold uppercase text-gray-400 tracking-wider">Estoque em Mãos</p>
                      <p className="text-2xl font-black text-gray-800 dark:text-white">
                          {currentProduct?.quantity.toLocaleString('pt-BR', { minimumFractionDigits: 0, maximumFractionDigits: 3 })}
                      </p>
                  </div>
                  <div className={`p-3 rounded-xl ${stockAction === 'in' ? 'bg-green-100 dark:bg-green-900/30 text-green-600' : 'bg-amber-100 dark:bg-amber-900/30 text-amber-600'}`}>
                      {stockAction === 'in' ? (
                          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 11l5-5m0 0l5 5m-5-5v12"></path></svg>
                      ) : (
                          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 13l-5 5m0 0l-5-5m5 5V6"></path></svg>
                      )}
                  </div>
              </div>

              <div>
                  <label className="block text-xs font-bold uppercase text-gray-500 mb-2">Quantidade para {stockAction === 'in' ? 'Entrada' : 'Saída'}</label>
                  <input 
                      type="number" 
                      value={stockQuantity} 
                      onChange={e => setStockQuantity(e.target.value)} 
                      min="0.001" 
                      step="0.001" 
                      placeholder="Ex: 0,68"
                      className="w-full p-4 text-xl font-bold border-2 rounded-2xl focus:ring-4 focus:ring-primary/10 transition-all dark:bg-gray-800 dark:border-gray-700 dark:text-gray-100" 
                  />

                  {/* BOTÕES DE FRAÇÃO RÁPIDA */}
                  <div className="flex flex-wrap gap-2 mt-3">
                      <FractionButton label="1/4" value={0.25} />
                      <FractionButton label="1/2" value={0.50} />
                      <FractionButton label="3/4" value={0.75} />
                      <FractionButton label="1 un" value={1.00} />
                  </div>
                  <p className="text-[10px] text-gray-400 mt-2 italic">Dica: Use os atalhos acima ou digite manualmente.</p>
              </div>

              {stockAction === 'out' && (
                  <div className="space-y-4 animate-fade-in">
                    <div>
                        <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Funcionário Responsável</label>
                        <select value={stockEmployeeId} onChange={e => setStockEmployeeId(e.target.value)} className={formInputClass}>
                            <option value="">Selecione quem está retirando...</option>
                            {employees.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
                        </select>
                    </div>
                    <div>
                        <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Vincular à Ordem de Serviço (Opcional)</label>
                        <select value={stockWorkOrderId} onChange={e => setStockWorkOrderId(e.target.value)} className={formInputClass}>
                            <option value="">Nenhuma / Uso Geral na Oficina</option>
                            {workOrders.map(wo => <option key={wo.id} value={wo.id}>{wo.title}</option>)}
                        </select>
                    </div>
                  </div>
              )}

              <div className="pt-2">
                  <button 
                      onClick={handleStockAction} 
                      className={`w-full py-4 rounded-2xl font-bold text-white shadow-xl transition-all active:scale-95 flex items-center justify-center space-x-2 ${stockAction === 'in' ? 'bg-green-600 hover:bg-green-700 shadow-green-500/20' : 'bg-amber-600 hover:bg-amber-700 shadow-amber-500/20'}`}
                  >
                      <span>Confirmar {stockAction === 'in' ? 'Entrada no Estoque' : 'Saída do Material'}</span>
                  </button>
                  <button onClick={() => setIsStockModalOpen(false)} className="w-full mt-2 py-2 text-sm text-gray-500 hover:text-red-500 transition">Cancelar Operação</button>
              </div>
          </div>
      </Modal>

      {currentProduct && (
        <QRCodeModal isOpen={isQrModalOpen} onClose={() => setIsQrModalOpen(false)} title={`QR Code: ${currentProduct.name}`} data={currentProduct.id} />
      )}
      <QRCodeScannerModal isOpen={isScannerOpen} onClose={() => setIsScannerOpen(false)} onScan={(data) => { setSearchTerm(data); addToast(`Produto ${data} localizado`, 'success'); }} addToast={addToast} />
    </div>
  );
};

{
  "name": "stock-sys-inteligente",
  "private": true,
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "tsc && vite build",
    "preview": "vite preview"
  },
  "dependencies": {
    "@google/genai": "^1.29.0",
    "@supabase/supabase-js": "^2.45.1",
    "react": "^18.3.1",
    "react-dom": "^18.3.1",
    "recharts": "^2.12.7",
    "html5-qrcode": "^2.3.8"
  },
  "devDependencies": {
    "@types/react": "^18.3.3",
    "@types/react-dom": "^18.3.0",
    "@vitejs/plugin-react": "^4.3.1",
    "typescript": "^5.2.2",
    "vite": "^5.4.1"
  }
}

import React, { useState, useMemo, FormEvent, useEffect, useCallback } from 'react';
import { PurchaseOrder, Supplier, Product, ToastMessage, User, StockMovement } from '../types';
import { Table, SortConfig } from './shared/Table';
import { Modal } from './shared/Modal';
import { useSupabase } from '../contexts/SupabaseContext';

interface PurchaseOrdersProps {
  addToast: (message: string, type: ToastMessage['type']) => void;
  showConfirmation: (message: string, onConfirm: () => void) => void;
  addActivityLog: (action: string) => void;
  currentUser: User;
}

export const PurchaseOrders: React.FC<PurchaseOrdersProps> = ({
  addToast, showConfirmation, addActivityLog
}) => {
  const supabase = useSupabase();
  const [purchaseOrders, setPurchaseOrders] = useState<PurchaseOrder[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [products, setProducts] = useState<Product[]>([]);

  // Estados para o Modal
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentOrder, setCurrentOrder] = useState<Partial<PurchaseOrder> | null>(null);
  const [itemSearch, setItemSearch] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<SortConfig<PurchaseOrder> | null>(null);

  const fetchData = useCallback(async () => {
    const [po, s, p] = await Promise.all([
        supabase.from('purchase_orders').select('*'),
        supabase.from('suppliers').select('*').order('name'),
        supabase.from('products').select('*').order('name'),
    ]);
    if(po.data) setPurchaseOrders(po.data as unknown as PurchaseOrder[]);
    if(s.data) setSuppliers(s.data);
    if(p.data) setProducts(p.data);
  }, [supabase]);

  useEffect(() => {
    fetchData();
    const channel = supabase.channel('purchase-orders-db-changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'purchase_orders' }, () => fetchData())
      .subscribe();
    return () => { supabase.removeChannel(channel); }
  }, [supabase, fetchData]);

  const addStockMovement = useCallback(async (movement: Omit<StockMovement, 'id' | 'date' | 'user_id'>) => {
    await supabase.from('stock_movements').insert({ ...movement, date: new Date().toISOString() });
  }, [supabase]);

  const sortedOrders = useMemo(() => {
    let sortableItems = [...purchaseOrders].filter(o => o.supplier_name.toLowerCase().includes(searchTerm.toLowerCase()));
    if (sortConfig !== null) {
      sortableItems.sort((a, b) => {
        const key = sortConfig.key;
        if (key === 'created_at') {
            return (new Date(a[key]).getTime() - new Date(b[key]).getTime()) * (sortConfig.direction === 'ascending' ? 1 : -1);
        }
        const valA = String(a[key] || '');
        const valB = String(b[key] || '');
        return valA.localeCompare(valB) * (sortConfig.direction === 'ascending' ? 1 : -1);
      });
    } else {
        sortableItems.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
    }
    return sortableItems;
  }, [purchaseOrders, searchTerm, sortConfig]);

  // Filtro de produtos para a busca dentro do modal
  const filteredProductsSearch = useMemo(() => {
    if (!itemSearch.trim()) return [];
    return products.filter(p => 
        p.name.toLowerCase().includes(itemSearch.toLowerCase()) || 
        p.id.toLowerCase().includes(itemSearch.toLowerCase())
    ).slice(0, 5); // Limita a 5 resultados para não poluir
  }, [products, itemSearch]);

  const openModal = (order: PurchaseOrder | null = null) => {
    setCurrentOrder(order ? { ...order } : { supplier_id: suppliers[0]?.id || '', items: [], status: 'pending' });
    setItemSearch('');
    setIsModalOpen(true);
  };

  const addItemToOrder = (product: Product) => {
      if (!currentOrder) return;
      const items = [...(currentOrder.items || [])];
      if (items.some(i => i.product_id === product.id)) {
          addToast("Este item já foi adicionado.", "warning");
          return;
      }
      items.push({ product_id: product.id, product_name: product.name, quantity: 1 });
      setCurrentOrder({ ...currentOrder, items });
      setItemSearch('');
  };

  const removeItemFromOrder = (productId: string) => {
      if (!currentOrder) return;
      const items = (currentOrder.items || []).filter(i => i.product_id !== productId);
      setCurrentOrder({ ...currentOrder, items });
  };

  const handleQtyChange = (productId: string, qty: number) => {
      if (!currentOrder) return;
      const items = (currentOrder.items || []).map(i => 
          i.product_id === productId ? { ...i, quantity: qty } : i
      );
      setCurrentOrder({ ...currentOrder, items });
  };

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    if (!currentOrder || !currentOrder.supplier_id || !currentOrder.items || currentOrder.items.length === 0) {
        addToast("Fornecedor e pelo menos um item são obrigatórios.", 'error');
        return;
    }
    const supplier = suppliers.find(s => s.id === currentOrder.supplier_id);
    if (!supplier) return;

    const orderData = {
        supplier_id: supplier.id,
        supplier_name: supplier.name,
        status: currentOrder.status || 'pending',
        items: currentOrder.items as any,
        created_at: currentOrder.id ? currentOrder.created_at! : new Date().toISOString()
    };

    const { error } = currentOrder.id 
        ? await supabase.from('purchase_orders').update(orderData).eq('id', currentOrder.id)
        : await supabase.from('purchase_orders').insert(orderData);

    if (error) { 
        addToast(`Erro: ${error.message}`, 'error'); 
    } else {
        addToast(`Ordem de Compra ${currentOrder.id ? 'atualizada' : 'criada'}!`, 'success');
        addActivityLog(`${currentOrder.id ? 'atualizou' : 'criou'} OC para ${supplier.name}.`);
        setIsModalOpen(false);
        fetchData();
    }
  }

  const handleReceiveOrder = (order: PurchaseOrder) => {
    showConfirmation("Confirmar o recebimento desta ordem? Os itens serão adicionados ao saldo do estoque.", async () => {
        try {
            for (const item of order.items) {
                const product = products.find(p => p.id === item.product_id);
                if (product) {
                    await supabase.from('products').update({ quantity: product.quantity + item.quantity }).eq('id', item.product_id);
                    await addStockMovement({
